import type { LocalizedTutorialContent } from '../tutorials-longform-i18n';

// Localized long-form content for one tutorial. Generated from validated
// per-locale translation JSONs; en renders from the Markdown source.
export const entry: Partial<Record<string, LocalizedTutorialContent>> = {
  "zh": {
    title: "从 Claude Design 迁移到 Open Design——无限制的搭建方式",
    summary: "一份摆脱 Claude Design 周限额的迁移手册：安装 Open Design、导入你的 Claude Design ZIP、用任意模型搭建、在项目进行中切换模型、加入 AI 生成图像、一键部署。还包含坦诚的「该不该切换」判断。基于 Jack Roberts 的实操演示整理。",
    bodyHtml: "<p>本指南是一份迁移手册，适合所有被 Claude Design 苛刻的周限额卡住的人：安装 Open Design、把你已有的成果搬过来、用你想用的任意模型搭建、在项目进行中切换模型、加入 AI 生成图像，再一键部署——而且全程在本地完成。它沿用 <strong>Jack Roberts</strong> 在<a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">他的实操演示</a>中走完的端到端迁移流程，重写并依据当前版本做了更新。想看实况就观看上方视频，想看图文版就继续往下读。</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/01-workspace.webp\" alt=\"Open Design 工作区——安装后你看到的第一个界面。\">\n<em>Open Design 工作区——原型、幻灯片、图像和视频，全部汇集在一块从容而熟悉的画布上。</em></p>\n<h2 id=\"why-migrate-at-all\">到底为什么要迁移？</h2>\n<p>Jack 的理由很直白：Claude Design 确实好用，但限额会让你寸步难行。你被锁定在单一模型（Opus 4.7）上，每周大约只能做出寥寥几个像样的设计，而且要在你本就有的编码开销之外，再每月付 20–200 美元。一旦你想用更便宜的模型、换个不同的模型，或是大规模地做设计，就会被处处掣肘。</p>\n<p>Open Design 拆掉了这些墙：</p>\n<ul>\n<li><strong>任意你想用的模型</strong>——而且可以在项目进行中切换。</li>\n<li><strong>没有周上限</strong>——生成依托于你本就在用的 agent 和服务商。</li>\n<li><strong>Apache-2.0</strong>——用于客户项目在商业上是安全的，这点不像那些采用限制性许可证的克隆仓库。</li>\n<li><strong>本地优先</strong>——什么都不上传；你的项目始终留在你自己的机器上。</li>\n</ul>\n<p>许可证这一点比听起来更重要：Jack 强调，好几个「Claude Design 克隆」其实根本不能用在客户项目里。Apache-2.0 意味着你可以交付用它搭建的付费成果，无需付版税、也无需获得许可。</p>\n<h2 id=\"step-1--install-open-design\">第一步——安装 Open Design</h2>\n<p>有三种入手方式：</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>方式</th><th>最适合</th><th>前置条件</th></tr></thead><tbody><tr><td><strong>桌面应用</strong></td><td>大多数人——零配置</td><td>无。下载打开即可。</td></tr><tr><td><strong>从源码运行</strong></td><td>想阅读或修改代码的开发者</td><td>Node <code>~24</code>，pnpm <code>10.33.x</code></td></tr><tr><td><strong>装进你的 agent</strong></td><td>常驻终端的人</td><td>一个已有的编码 agent CLI</td></tr></tbody></table>\n<p>最简单的方式是从 <a href=\"https://open-design.ai/download\">open-design.ai/download</a> 下载<strong>桌面应用</strong>——它会自动检测你已安装的 agent CLI。在视频里，Jack 走的是开发者路线，把仓库交给他的 agent，让它去克隆并运行：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>它会打开自带的本地 web 应用——一个你自己本地托管、类似 Claude Design 的工作区——地址就在它打印出的那个动态 URL 上（不要把端口写死）。</p>\n<h2 id=\"step-2--bring-your-claude-design-work-across\">第二步——把你的 Claude Design 成果搬过来</h2>\n<p>这是大家最想要的迁移步骤：<strong>导入你的 Claude Design 项目</strong>。如果你在 Claude Design 里搭过设计系统或项目，可以直接搬过来——在那边打开它，把项目下载为 ZIP，再在 Open Design 里导入这个 ZIP。你的 token 和组件都会一起带过来，所以不用从头重建。</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/02-design-systems.webp\" alt=\"内置的设计系统库——真实品牌的起点。\">\n<em>设计系统库：每一条都把一个真实品牌拆解成调色板、排版、组件和视觉氛围，供你复用。</em></p>\n<p>你还会继承一个内容丰富的内置设计系统库——Airbnb、Apple、Nike、PlayStation 等等——所以哪怕什么都不导入，你也可以挑一个品牌，让 agent 继承它的调性、排版、配色和布局语言。</p>\n<h2 id=\"step-3--build-with-the-model-you-choose\">第三步——用你选择的模型搭建</h2>\n<p>首次启动时，Open Design 会显示你机器上已经安装的 agent。Jack 选了 Claude Code，给项目起名（「analytics」），选了高保真度，并写下一段需求简介，要做一个 Stripe 风格的仪表盘。Open Design 抛出它的澄清式提问——界面、主要受众、调性、范围、强调色——然后逐项走完一个待办清单，一次性产出一个可交互的仪表盘。再来一轮反馈，就能让它达到可上线的状态。</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/03-templates.webp\" alt=\"模板库——原型、幻灯片、图像和视频的起点。\">\n<em>模板库：原型、幻灯片、图像和视频的起点，你可以按类型筛选，并 fork 一份开始动手。</em></p>\n<h2 id=\"step-4--switch-models-mid-project\">第四步——在项目进行中切换模型</h2>\n<p>这是 Jack 最爱的一招，也是 Claude Design 做不到的。在项目进行中，打开模型切换器（左下角），从 Claude Code 切到 <strong>Codex</strong>（或 ChatGPT、Gemini，任何你接入过的模型），然后保存。现在你的下一条消息——「把实时事件流弄顺一点，它看着有卡顿」——就由新模型来处理，还是同一个项目，还是同样的上下文。</p>\n<p>他的高手心得：<strong>用 Opus 来确立最初的设计，再切到更便宜的模型去迭代和扩量。</strong>对一个模型来说，照着同一种风格做更多，远比从第一性原理把一种观感从头设计出来要容易，所以让最强的模型搭好架构，再让便宜的模型去跑量。</p>\n<h2 id=\"step-5--add-ai-images-and-deploy\">第五步——加入 AI 生成图像并部署</h2>\n<p>在设置里加上一个媒体服务商密钥（比如用 OpenAI 来调 GPT Image），你就能在对话中直接要求生成图像——「在其中一个方框里加一张吉卜力风格的投资存钱罐图片」——它会连同渐变效果一起直接落进设计里。这种内联生成，是纯粹的设计克隆品给不了你的。</p>\n<p>做完之后，<strong>Share</strong> 会给你完整的导出菜单：独立 HTML、PowerPoint、PDF、ZIP、另存为模板——或者用你的 token <strong>直接部署到 Vercel</strong>。下载成 ZIP，你也可以在 Codex、Claude 或你惯用的编辑器里重新打开它。</p>\n<h2 id=\"when-to-switch-and-when-not-to\">什么时候该切换（什么时候不该）</h2>\n<p>Jack 对适用场景很坦诚。如果你是需要商业安全产出的<strong>代理机构或自由职业者</strong>、是已经在为 Claude Code / Codex / Cursor 付费的<strong>多模型操盘手</strong>，或者你正在<strong>把 Claude Design 的周上限烧光</strong>、只想做更多设计，那就切到 Open Design。如果你刚接触这一切、又满足于它的限额之内，那暂时继续用 Claude Design。</p>\n<p>一点提醒：Open Design 是一个年轻、迭代迅速的项目，所以要预料到偶尔会有些粗糙的地方，多给它一点宽容——它在快速变好。</p>\n<h2 id=\"tips\">小贴士</h2>\n<ul>\n<li><strong>先导入你的 Claude Design ZIP</strong>——别重建一个你已经有的系统。</li>\n<li><strong>用 Opus 定下观感，再切到更便宜的模型</strong>去迭代和扩量。</li>\n<li><strong>加一个媒体密钥</strong>来获得内联 AI 图像——相比静态设计工具是实打实的升级。</li>\n<li><strong>用本地 CLI</strong>，让生成依托于你已经在付费的订阅，而不是按次调用收费。</li>\n<li><strong>尽早导出</strong>（HTML/ZIP/Vercel）来做验证，再交付出去。</li>\n</ul>\n<h2 id=\"faq\">常见问题</h2>\n<p><strong>我的 Claude Design 项目能迁移过来吗？</strong>\n能。从 Claude Design 把你的项目下载为 ZIP，再把这个 ZIP 导入 Open Design——token 和组件都会带过来。</p>\n<p><strong>我真的可以用任意模型吗？</strong>\n可以——从你机器上已安装的 agent 中挑选（Claude Code、Codex、Gemini、Cursor、OpenCode 等等），在项目进行中相互切换，或者用你自己的 API 密钥。</p>\n<p><strong>用于客户项目安全吗？</strong>\n安全。Open Design 采用 Apache-2.0，所以你可以商用，无需付版税、也无需获得许可——这点不像某些采用限制性许可证的克隆品。</p>\n<p><strong>它免费吗？</strong>\n这个应用以 Apache-2.0 开源，本地运行免费。你只需为你接入的 agent 和服务商所产生的模型与媒体用量付费——而这恰恰是你摆脱固定月度上限的方式。</p>\n<hr>\n<p><em>这份图文指南基于 Jack Roberts 的实操演示。观看上方完整视频，并<a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">订阅 Jack Roberts</a>，获取更多务实的 AI 搭建拆解。</em></p>",
  },
  "ja": {
    title: "Claude Design から Open Design への移行 — 無制限の環境を手に入れる",
    summary: "Claude Design の週ごとの制限から解放されるための移行ガイド。Open Design をインストールし、Claude Design の ZIP をインポートし、好きなモデルで制作し、プロジェクトの途中でモデルを切り替え、AI 画像を追加し、デプロイするまでを解説します。「いつ乗り換えるべきか」という率直な判断も収録。Jack Roberts による実践的なウォークスルーに基づいています。",
    bodyHtml: "<p>このガイドは、Claude Design の厳しい週ごとの制限にぶつかっているすべての人のための移行プレイブックです。Open Design をインストールし、既存の作業を持ち込み、好きなモデルで制作し、プロジェクトの途中でモデルを切り替え、AI 画像を追加し、デプロイする — そのすべてをローカルで行えます。これは <strong>Jack Roberts</strong> が<a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">実践的なウォークスルー</a>で実演しているエンドツーエンドの移行を、最新リリースに合わせて書き直しアップデートしたものです。ライブ実演は上の動画をご覧いただくか、テキスト版を読み進めてください。</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/01-workspace.webp\" alt=\"Open Design のワークスペース — インストール後に最初に表示される画面。\">\n<em>Open Design のワークスペース — プロトタイプ、スライドデッキ、画像、動画が、落ち着いた見慣れた一つのキャンバスにまとまっています。</em></p>\n<h2 id=\"why-migrate-at-all\">そもそもなぜ移行するのか？</h2>\n<p>Jack の主張は率直です。Claude Design は本当に優れているが、制限が手を止めてしまう、と。使えるモデルは一つ（Opus 4.7）に固定され、意味のあるデザインは週におよそ数件までに制限され、しかもすでに支払っているコーディング費用に加えて月額 $20〜$200 を払うことになります。より安いモデル、別のモデル、あるいは大規模にデザインしたいと思った瞬間、足止めを食らうのです。</p>\n<p>Open Design はそうした壁を取り払います。</p>\n<ul>\n<li><strong>好きなモデルをどれでも</strong> — しかもプロジェクトの途中で切り替えられます。</li>\n<li><strong>週ごとの上限なし</strong> — 生成はすでに使っているエージェントとプロバイダーに乗ります。</li>\n<li><strong>Apache-2.0</strong> — 制限の厳しいライセンスのクローンリポジトリとは違い、クライアントワークでも商用利用が安全です。</li>\n<li><strong>ローカルファースト</strong> — 何もアップロードされず、プロジェクトは自分のマシンに留まります。</li>\n</ul>\n<p>このライセンスの点は、聞こえる以上に重要です。Jack は、いくつかの「Claude Design クローン」は実際にはクライアントプロジェクトで使えないと強調します。Apache-2.0 なら、それで作った有償の仕事を、ロイヤリティも許諾も不要で世に出せます。</p>\n<h2 id=\"step-1--install-open-design\">ステップ 1 — Open Design をインストールする</h2>\n<p>入り口は 3 通りあります。</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>方法</th><th>向いている人</th><th>必要なもの</th></tr></thead><tbody><tr><td><strong>デスクトップアプリ</strong></td><td>ほとんどの人 — 設定不要</td><td>なし。ダウンロードして開くだけ。</td></tr><tr><td><strong>ソースから実行</strong></td><td>コードを読んだり改変したい開発者</td><td>Node <code>~24</code>、pnpm <code>10.33.x</code></td></tr><tr><td><strong>エージェントに組み込む</strong></td><td>ターミナルで暮らす人</td><td>既存のコーディングエージェント CLI</td></tr></tbody></table>\n<p>最もシンプルなのは <a href=\"https://open-design.ai/download\">open-design.ai/download</a> からの<strong>デスクトップアプリ</strong>です — インストール済みのエージェント CLI を自動検出します。動画では、Jack は開発者向けのルートを選び、リポジトリをエージェントに渡してクローンと実行を任せています。</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>これは独自のローカル Web アプリ — 自分のマシンでホストされる Claude Design ライクなワークスペース — を、出力される動的な URL で開きます（ポートをハードコードしないでください）。</p>\n<h2 id=\"step-2--bring-your-claude-design-work-across\">ステップ 2 — Claude Design の作業を持ち込む</h2>\n<p>みんなが最も求めている移行ステップ、それが <strong>Claude Design プロジェクトのインポート</strong>です。Claude Design でデザインシステムやプロジェクトを作ったなら、そのまま持ち越せます — Claude Design で開いてプロジェクトを ZIP としてダウンロードし、その ZIP を Open Design でインポートするだけ。トークンやコンポーネントも一緒に移るので、ゼロから作り直す必要はありません。</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/02-design-systems.webp\" alt=\"組み込みのデザインシステムライブラリ — 実在ブランドの出発点。\">\n<em>デザインシステムライブラリ：各エントリは実在のブランドをパレット、タイポグラフィ、コンポーネント、そして再利用できるビジュアルの雰囲気にまで分解しています。</em></p>\n<p>さらに、奥行きのある組み込みのデザインシステムライブラリも受け継げます — Airbnb、Apple、Nike、PlayStation など多数 — なので、何もインポートしなくても、ブランドを選べばエージェントがそのボイス、タイポグラフィ、パレット、レイアウトの言語を受け継ぎます。</p>\n<h2 id=\"step-3--build-with-the-model-you-choose\">ステップ 3 — 選んだモデルで制作する</h2>\n<p>初回起動時、Open Design はマシンにインストール済みのエージェントを表示します。Jack は Claude Code を選び、プロジェクトに名前（「analytics」）を付け、高忠実度を選択し、Stripe 風のダッシュボードのブリーフを書きます。Open Design は明確化のための質問 — 画面、主な閲覧者、トーン、スコープ、アクセント — を投げかけ、To-Do リストを順にこなして、一発でインタラクティブなダッシュボードを生み出します。2 回目のフィードバックでプロダクション対応に仕上がります。</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/03-templates.webp\" alt=\"テンプレートライブラリ — プロトタイプ、スライド、画像、動画の出発点。\">\n<em>テンプレートライブラリ：プロトタイプ、スライド、画像、動画の出発点を、種類で絞り込みフォークして始められます。</em></p>\n<h2 id=\"step-4--switch-models-mid-project\">ステップ 4 — プロジェクトの途中でモデルを切り替える</h2>\n<p>これは Jack のお気に入りの一手であり、Claude Design にはできないことです。プロジェクトの途中で、（左下の）モデルスイッチャーを開き、Claude Code から <strong>Codex</strong>（あるいは ChatGPT、Gemini、接続済みのものなら何でも）に変更して保存します。すると次のメッセージ — 「ライブイベントのストリームを滑らかにして、カクついて見える」 — は、同じプロジェクトで、同じコンテキストのまま、新しいモデルが処理します。</p>\n<p>彼のプロのコツはこうです。<strong>Opus で最初のデザインを確立し、それから安いモデルに切り替えてイテレーションと拡張を行う。</strong>モデルにとって、原理から見た目を組み立てるよりも、同じものを増やす方がはるかに簡単です。だから最も強力なモデルにアーキテクチャを定めさせ、安いモデルに量をこなさせましょう。</p>\n<h2 id=\"step-5--add-ai-images-and-deploy\">ステップ 5 — AI 画像を追加してデプロイする</h2>\n<p>設定でメディアプロバイダーのキー（たとえば GPT Image 用の OpenAI）を追加すれば、インラインで生成画像をリクエストできます — 「ボックスの一つに、ジブリ風の投資用ブタの貯金箱の画像を追加して」 — すると、グラデーションまで含めてそのままデザインに落とし込まれます。このインライン生成は、純粋なデザインクローンでは得られないものです。</p>\n<p>完成したら、<strong>共有</strong>からフルのエクスポートメニューが開きます。スタンドアロンの HTML、PowerPoint、PDF、ZIP、テンプレートとして保存 — あるいはトークンを使って <strong>Vercel に直接デプロイ</strong>。ZIP としてダウンロードすれば、Codex、Claude、あるいはお好みのエディタで開き直すこともできます。</p>\n<h2 id=\"when-to-switch-and-when-not-to\">いつ乗り換えるべきか（そして、いつそうでないか）</h2>\n<p>Jack は相性について正直です。商用利用が安全な成果物を必要とする<strong>エージェンシーやフリーランサー</strong>、すでに Claude Code / Codex / Cursor に課金している<strong>マルチモデル運用者</strong>、あるいは <strong>Claude Design の週ごとの上限を使い切って</strong>もっとデザインしたいだけの人なら、Open Design に乗り換えましょう。これらすべてに初めて触れる人で、その制限の中で満足しているなら、当面は Claude Design のままで構いません。</p>\n<p>一つだけ注意点を。Open Design は若く、急速に進化中のプロジェクトなので、時折の粗さは想定しておき、大目に見てあげてください — 改善のスピードは速いです。</p>\n<h2 id=\"tips\">コツ</h2>\n<ul>\n<li><strong>まず Claude Design の ZIP をインポートする</strong> — すでにあるシステムを作り直さないこと。</li>\n<li><strong>Opus で見た目を定めてから、安いモデルに切り替える</strong> — イテレーションと拡張のために。</li>\n<li><strong>メディアキーを追加する</strong> — インライン AI 画像を得られ、静的なデザインツールからの本物のアップグレードになります。</li>\n<li><strong>ローカル CLI を使う</strong> — 生成が、呼び出しごとの課金ではなく、すでに支払っているサブスクリプションに乗るように。</li>\n<li><strong>早めにエクスポートする</strong>（HTML/ZIP/Vercel） — 引き渡す前に検証するために。</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Claude Design のプロジェクトは移行できますか？</strong>\nはい。Claude Design からプロジェクトを ZIP としてダウンロードし、その ZIP を Open Design にインポートします — トークンとコンポーネントが引き継がれます。</p>\n<p><strong>本当にどんなモデルでも使えますか？</strong>\nはい — マシンにインストール済みのエージェント（Claude Code、Codex、Gemini、Cursor、OpenCode など）から選び、プロジェクトの途中で切り替えるか、自分の API キーを持ち込めます。</p>\n<p><strong>クライアントワークで安全に使えますか？</strong>\nはい。Open Design は Apache-2.0 なので、制限の厳しいライセンスの一部のクローンとは違い、ロイヤリティも許諾も不要で商用利用できます。</p>\n<p><strong>無料ですか？</strong>\nアプリは Apache-2.0 のオープンソースで、ローカルでの実行は無料です。支払うのは、接続したエージェントとプロバイダーのモデルおよびメディアの利用分だけ — これこそが、固定の月額上限から抜け出す方法そのものです。</p>\n<hr>\n<p><em>このテキストガイドは Jack Roberts の実践的なウォークスルーに基づいています。上のフル動画をご覧いただき、実践的な AI 構築の解説をもっと見たい方は <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">Jack Roberts をフォロー</a>してください。</em></p>",
  },
  "ko": {
    title: "Claude Design에서 Open Design으로 이전하기 — 무제한 환경 구축하기",
    summary: "Claude Design의 주간 제한을 벗어나기 위한 마이그레이션 플레이북 — Open Design 설치, Claude Design ZIP 가져오기, 원하는 모델로 빌드, 프로젝트 중간에 모델 전환, AI 이미지 추가, 배포까지. \"언제 갈아타야 하는가\"에 대한 솔직한 판단도 함께 담았습니다. Jack Roberts의 실습 워크스루를 기반으로 합니다.",
    bodyHtml: "<p>이 가이드는 Claude Design의 가혹한 주간 제한에 부딪힌 모든 사람을 위한 마이그레이션 플레이북입니다. Open Design을 설치하고, 기존 작업물을 그대로 옮기고, 원하는 어떤 모델로든 빌드하고, 프로젝트 도중에 모델을 전환하고, AI 이미지를 추가하고, 배포까지 — 모두 로컬에서 진행합니다. <strong>Jack Roberts</strong>가 <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">실습 워크스루</a>에서 진행하는 엔드투엔드 마이그레이션을 따르되, 현재 릴리스에 맞춰 다시 쓰고 최신 내용으로 업데이트했습니다. 실제 실행 과정은 위 영상을 보시고, 글로 된 버전은 아래에서 읽어 보세요.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/01-workspace.webp\" alt=\"Open Design 워크스페이스 — 설치 후 처음 마주하게 되는 화면.\">\n<em>Open Design 워크스페이스 — 프로토타입, 슬라이드 덱, 이미지, 영상이 차분하고 익숙한 하나의 캔버스에 모여 있습니다.</em></p>\n<h2 id=\"why-migrate-at-all\">왜 굳이 이전해야 할까?</h2>\n<p>Jack의 주장은 직설적입니다. Claude Design은 정말 훌륭하지만, 제한 때문에 발이 묶입니다. 하나의 모델(Opus 4.7)에 갇혀 있고, 일주일에 의미 있는 디자인을 대략 두어 개 정도밖에 만들 수 없으며, 이미 코딩에 쓰는 비용에 더해 월 $20–$200을 내야 합니다. 더 저렴한 모델이나 다른 모델을 쓰고 싶거나, 대규모로 디자인하고 싶은 순간 막혀 버립니다.</p>\n<p>Open Design은 그 벽을 허뭅니다:</p>\n<ul>\n<li><strong>원하는 어떤 모델이든</strong> — 게다가 프로젝트 도중에 전환할 수 있습니다.</li>\n<li><strong>주간 한도 없음</strong> — 생성은 이미 사용 중인 에이전트와 제공업체를 통해 이뤄집니다.</li>\n<li><strong>Apache-2.0</strong> — 제한적인 라이선스를 가진 클론 저장소와 달리, 클라이언트 작업에 상업적으로 안전합니다.</li>\n<li><strong>로컬 우선</strong> — 아무것도 업로드되지 않고, 프로젝트는 여러분의 컴퓨터에 남습니다.</li>\n</ul>\n<p>이 라이선스 포인트는 들리는 것보다 훨씬 중요합니다. Jack은 여러 “Claude Design 클론”들이 실제로는 클라이언트 프로젝트에 사용될 수 없다는 점을 강조합니다. Apache-2.0는 그것으로 만든 유료 작업물을 출시할 수 있다는 뜻이며, 로열티도 허가도 필요 없습니다.</p>\n<h2 id=\"step-1--install-open-design\">1단계 — Open Design 설치하기</h2>\n<p>들어가는 방법은 세 가지입니다:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>방법</th><th>적합한 대상</th><th>요구 사항</th></tr></thead><tbody><tr><td><strong>데스크톱 앱</strong></td><td>대부분의 사용자 — 설정 불필요</td><td>없음. 다운로드 후 열기만 하면 됩니다.</td></tr><tr><td><strong>소스에서 실행</strong></td><td>코드를 읽거나 수정하고 싶은 개발자</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>에이전트에 설치</strong></td><td>터미널에서 작업하는 사람</td><td>이미 설치된 코딩 에이전트 CLI</td></tr></tbody></table>\n<p>가장 간단한 방법은 <a href=\"https://open-design.ai/download\">open-design.ai/download</a>에서 받는 <strong>데스크톱 앱</strong>입니다 — 설치된 에이전트 CLI를 자동으로 감지합니다. 영상에서 Jack은 저장소를 자신의 에이전트에게 넘겨 클론하고 실행하게 함으로써 개발자 방식을 택합니다:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>그러면 자체 로컬 웹 앱이 열립니다 — 여러분만의 로컬 호스팅 Claude Design 같은 워크스페이스가 — 출력되는 동적 URL에서 (포트를 하드코딩하지 마세요).</p>\n<h2 id=\"step-2--bring-your-claude-design-work-across\">2단계 — Claude Design 작업물 그대로 옮기기</h2>\n<p>사람들이 가장 원하는 마이그레이션 단계: <strong>Claude Design 프로젝트 가져오기</strong>. Claude Design에서 디자인 시스템이나 프로젝트를 만들었다면 그대로 옮겨 올 수 있습니다 — 거기서 열어 프로젝트를 ZIP으로 다운로드한 다음, 그 ZIP을 Open Design에서 가져오면 됩니다. 토큰과 컴포넌트가 함께 따라오므로, 처음부터 다시 만들 필요가 없습니다.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/02-design-systems.webp\" alt=\"내장 디자인 시스템 라이브러리 — 실제 브랜드 출발점.\">\n<em>디자인 시스템 라이브러리: 각 항목은 실제 브랜드를 팔레트, 타이포그래피, 컴포넌트, 그리고 재사용 가능한 시각적 분위기로 분해해 보여 줍니다.</em></p>\n<p>또한 깊이 있는 내장 디자인 시스템 라이브러리도 함께 받습니다 — Airbnb, Apple, Nike, PlayStation을 비롯한 다수가 포함되어 있어, 아무것도 가져오지 않더라도 브랜드 하나를 고르면 에이전트가 그 브랜드의 목소리, 타이포그래피, 팔레트, 레이아웃 언어를 그대로 물려받습니다.</p>\n<h2 id=\"step-3--build-with-the-model-you-choose\">3단계 — 직접 고른 모델로 빌드하기</h2>\n<p>처음 실행하면 Open Design은 여러분의 컴퓨터에 이미 설치된 에이전트들을 보여 줍니다. Jack은 Claude Code를 고르고, 프로젝트 이름을 (“analytics”로) 정한 뒤, 높은 충실도를 선택하고, Stripe 스타일 대시보드에 대한 브리프를 작성합니다. Open Design은 명확히 하기 위한 질문들을 던지고 — 화면, 주 사용자, 톤, 범위, 강조색 — 그런 다음 할 일 목록을 차례로 처리하며 인터랙티브 대시보드를 단번에 만들어 냅니다. 두 번째 피드백을 거치면 프로덕션에 쓸 수 있는 수준이 됩니다.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/03-templates.webp\" alt=\"템플릿 라이브러리 — 프로토타입, 슬라이드, 이미지, 영상 출발점.\">\n<em>템플릿 라이브러리: 프로토타입, 슬라이드, 이미지, 영상 출발점을 유형별로 필터링하고 포크해 시작할 수 있습니다.</em></p>\n<h2 id=\"step-4--switch-models-mid-project\">4단계 — 프로젝트 중간에 모델 전환하기</h2>\n<p>이것이 Jack이 가장 좋아하는 기능이자 Claude Design이 할 수 없는 일입니다. 프로젝트 도중에 모델 전환기(왼쪽 하단)를 열어 Claude Code에서 <strong>Codex</strong>로 (또는 ChatGPT, Gemini 등 연결해 둔 무엇이든) 바꾸고 저장합니다. 이제 다음 메시지 — “라이브 이벤트 스트림을 부드럽게 해 줘, 끊겨 보여” — 는 같은 프로젝트, 같은 맥락에서 새 모델이 처리합니다.</p>\n<p>그의 프로 팁: <strong>Opus로 초기 디자인을 잡은 다음, 더 저렴한 모델로 전환해 반복하고 확장하라.</strong> 모델 입장에서는 처음부터 새로운 외관을 설계하는 것보다 같은 것을 더 많이 만들어 내는 편이 훨씬 쉽습니다. 그러니 가장 강력한 모델에게 아키텍처를 잡게 하고, 더 저렴한 모델들에게 물량을 맡기세요.</p>\n<h2 id=\"step-5--add-ai-images-and-deploy\">5단계 — AI 이미지 추가하고 배포하기</h2>\n<p>설정에서 미디어 제공업체 키(예: GPT Image용 OpenAI)를 추가하면, 인라인으로 생성된 이미지를 요청할 수 있습니다 — “박스 중 하나에 투자용 돼지 저금통의 Ghibli 스타일 이미지를 넣어 줘” — 그러면 그라데이션까지 포함해 디자인에 바로 들어갑니다. 이런 인라인 생성은 순수한 디자인 클론으로는 누릴 수 없는 기능입니다.</p>\n<p>작업이 끝나면 <strong>Share</strong>가 전체 내보내기 메뉴를 제공합니다: 독립 실행형 HTML, PowerPoint, PDF, ZIP, 템플릿으로 저장 — 또는 토큰을 사용해 <strong>Vercel로 바로 배포</strong>. ZIP으로 다운로드하면 Codex, Claude, 혹은 원하는 에디터에서 다시 열 수도 있습니다.</p>\n<h2 id=\"when-to-switch-and-when-not-to\">언제 갈아타야 하고, 언제 그러지 말아야 하는가</h2>\n<p>Jack은 적합성에 대해 솔직합니다. 상업적으로 안전한 결과물이 필요한 <strong>에이전시나 프리랜서</strong>이거나, 이미 Claude Code / Codex / Cursor에 비용을 내고 있는 <strong>멀티 모델 운영자</strong>이거나, <strong>Claude Design의 주간 한도를 다 써 버리며</strong> 그저 더 많은 디자인을 원한다면 Open Design으로 갈아타세요. 이 모든 것이 아직 처음이고 그 제한 안에서 만족한다면, 지금은 Claude Design을 계속 쓰세요.</p>\n<p>한 가지 주의할 점: Open Design은 빠르게 발전하는 신생 프로젝트라, 가끔은 거친 부분이 있을 수 있으니 너그럽게 봐 주세요 — 빠르게 개선되고 있습니다.</p>\n<h2 id=\"tips\">팁</h2>\n<ul>\n<li><strong>Claude Design ZIP부터 가져오세요</strong> — 이미 가지고 있는 시스템을 다시 만들지 마세요.</li>\n<li><strong>Opus로 외관을 잡은 다음, 더 저렴한 모델로 전환해</strong> 반복하고 확장하세요.</li>\n<li><strong>미디어 키를 추가</strong>해 인라인 AI 이미지를 얻으세요 — 정적인 디자인 도구에 비하면 진정한 업그레이드입니다.</li>\n<li><strong>로컬 CLI를 사용</strong>해 생성이 호출당 요금이 아니라 이미 내고 있는 구독을 통해 이뤄지게 하세요.</li>\n<li><strong>일찍 내보내</strong>(HTML/ZIP/Vercel) 넘기기 전에 검증하세요.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>제 Claude Design 프로젝트가 이전되나요?</strong>\n네. Claude Design에서 프로젝트를 ZIP으로 다운로드한 뒤 그 ZIP을 Open Design으로 가져오세요 — 토큰과 컴포넌트가 그대로 옮겨집니다.</p>\n<p><strong>정말로 어떤 모델이든 쓸 수 있나요?</strong>\n네 — 컴퓨터에 설치된 에이전트들(Claude Code, Codex, Gemini, Cursor, OpenCode 등) 중에서 고르고, 프로젝트 도중에 서로 전환하거나, 직접 API 키를 가져오면 됩니다.</p>\n<p><strong>클라이언트 작업에 안전한가요?</strong>\n네. Open Design은 Apache-2.0이므로, 로열티나 허가 없이 상업적으로 사용할 수 있습니다 — 제한적인 라이선스를 가진 일부 클론과 달리 말이죠.</p>\n<p><strong>무료인가요?</strong>\n앱은 Apache-2.0 하에 오픈 소스이며 로컬에서 무료로 실행됩니다. 연결한 에이전트와 제공업체의 모델 및 미디어 사용량에 대해서만 비용을 내면 됩니다 — 이것이 바로 고정된 월 한도에서 벗어나는 방법입니다.</p>\n<hr>\n<p><em>이 글로 된 가이드는 Jack Roberts의 실습 워크스루를 기반으로 합니다. 위의 전체 영상을 시청하시고, 더 실용적인 AI 빌드 분석을 원하신다면 <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">Jack Roberts를 구독</a>하세요.</em></p>",
  },
  "de": {
    title: "Von Claude Design zu Open Design wechseln — das unbegrenzte Setup",
    summary: "Ein Migrations-Playbook, um die wöchentlichen Limits von Claude Design hinter sich zu lassen — Open Design installieren, das Claude-Design-ZIP importieren, mit jedem beliebigen Modell bauen, das Modell mitten im Projekt wechseln, KI-Bilder ergänzen und deployen. Inklusive der ehrlichen Einschätzung, wann sich ein Wechsel lohnt. Basierend auf der praxisnahen Anleitung von Jack Roberts.",
    bodyHtml: "<p>Dieser Leitfaden ist ein Migrations-Playbook für alle, die an die brutalen wöchentlichen Limits von Claude Design stoßen: Open Design installieren, vorhandene Arbeit übernehmen, mit jedem gewünschten Modell bauen, das Modell mitten im Projekt wechseln, KI-Bilder ergänzen und deployen — alles lokal. Er folgt der durchgängigen Migration, die <strong>Jack Roberts</strong> in <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">seiner praxisnahen Anleitung</a> durchführt, neu geschrieben und auf den Stand des aktuellen Release gebracht. Sieh dir das Video oben für den Live-Durchlauf an oder lies weiter für die schriftliche Fassung.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/01-workspace.webp\" alt=\"Der Open-Design-Arbeitsbereich — das, was dich nach der Installation erwartet.\">\n<em>Der Open-Design-Arbeitsbereich — Prototypen, Foliendecks, Bilder und Videos auf einer ruhigen, vertrauten Leinwand.</em></p>\n<h2 id=\"why-migrate-at-all\">Warum überhaupt migrieren?</h2>\n<p>Jacks Argument ist unmissverständlich: Claude Design ist wirklich gut, aber die Limits bremsen dich komplett aus. Du bist an ein einziges Modell gebunden (Opus 4.7), auf rund ein paar nennenswerte Designs pro Woche begrenzt und zahlst 20–200 $/Monat zusätzlich zu dem, was du ohnehin schon fürs Programmieren ausgibst. Sobald du ein günstigeres Modell, ein anderes Modell oder Design in großem Maßstab willst, wirst du ausgebremst.</p>\n<p>Open Design reißt diese Mauern ein:</p>\n<ul>\n<li><strong>Jedes gewünschte Modell</strong> — und du kannst mitten im Projekt wechseln.</li>\n<li><strong>Kein wöchentliches Limit</strong> — die Generierung läuft über den Agent und die Anbieter, die du ohnehin nutzt.</li>\n<li><strong>Apache-2.0</strong> — kommerziell unbedenklich für Kundenarbeit, anders als Klon-Repos mit restriktiven Lizenzen.</li>\n<li><strong>Local-First</strong> — nichts wird hochgeladen; deine Projekte bleiben auf deinem Rechner.</li>\n</ul>\n<p>Dieser Lizenzpunkt zählt mehr, als er klingt: Jack betont, dass mehrere „Claude-Design-Klone“ in Kundenprojekten gar nicht eingesetzt werden dürfen. Apache-2.0 bedeutet, dass du damit erstellte bezahlte Arbeit ausliefern darfst — keine Lizenzgebühren, keine Genehmigung nötig.</p>\n<h2 id=\"step-1--install-open-design\">Schritt 1 — Open Design installieren</h2>\n<p>Drei Wege hinein:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Weg</th><th>Am besten für</th><th>Voraussetzungen</th></tr></thead><tbody><tr><td><strong>Desktop-App</strong></td><td>Die meisten — ohne Konfiguration</td><td>Keine. Einfach herunterladen und öffnen.</td></tr><tr><td><strong>Aus dem Quellcode ausführen</strong></td><td>Entwickler, die den Code lesen oder anpassen wollen</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>In deinen Agent integrieren</strong></td><td>Menschen, die im Terminal leben</td><td>Eine vorhandene Coding-Agent-CLI</td></tr></tbody></table>\n<p>Der einfachste Weg ist die <strong>Desktop-App</strong> von <a href=\"https://open-design.ai/download\">open-design.ai/download</a> — sie erkennt deine installierten Agent-CLIs automatisch. Im Video geht Jack den Entwicklerweg, indem er das Repo an seinen Agent übergibt und ihn klonen und ausführen lässt:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Es öffnet seine eigene lokale Web-App — deinen eigenen, lokal gehosteten, Claude-Design-ähnlichen Arbeitsbereich — unter der dynamischen URL, die es ausgibt (den Port nicht fest einprogrammieren).</p>\n<h2 id=\"step-2--bring-your-claude-design-work-across\">Schritt 2 — Deine Claude-Design-Arbeit mitnehmen</h2>\n<p>Der Migrationsschritt, den sich die meisten am meisten wünschen: <strong>dein Claude-Design-Projekt importieren</strong>. Wenn du ein Designsystem oder Projekt in Claude Design erstellt hast, kannst du es direkt übernehmen — öffne es dort, lade das Projekt als ZIP herunter und importiere dieses ZIP dann in Open Design. Deine Tokens und Komponenten kommen mit, sodass du nicht von Grund auf neu bauen musst.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/02-design-systems.webp\" alt=\"Die integrierte Designsystem-Bibliothek — echte Marken als Ausgangspunkt.\">\n<em>Die Designsystem-Bibliothek: Jeder Eintrag zerlegt eine echte Marke in Farbpalette, Typografie, Komponenten und visuelle Atmosphäre, die du wiederverwenden kannst.</em></p>\n<p>Außerdem erbst du eine umfangreiche integrierte Designsystem-Bibliothek — Airbnb, Apple, Nike, PlayStation und viele mehr —, sodass du selbst ohne irgendetwas zu importieren eine Marke auswählen kannst und der Agent ihre Tonalität, Typografie, Farbpalette und Layoutsprache übernimmt.</p>\n<h2 id=\"step-3--build-with-the-model-you-choose\">Schritt 3 — Mit dem Modell deiner Wahl bauen</h2>\n<p>Beim ersten Start zeigt Open Design die bereits auf deinem Rechner installierten Agents an. Jack wählt Claude Code, benennt ein Projekt („analytics“), entscheidet sich für hohe Detailtreue und schreibt ein Briefing für ein Dashboard im Stripe-Stil. Open Design stellt seine klärenden Fragen — Oberfläche, primäre Zielgruppe, Tonalität, Umfang, Akzentfarbe — arbeitet sich dann durch eine To-do-Liste und liefert ein interaktives Dashboard in einem Durchgang. Eine zweite Feedback-Runde macht es produktionsreif.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/03-templates.webp\" alt=\"Die Vorlagenbibliothek — Ausgangspunkte für Prototyp, Folie, Bild und Video.\">\n<em>Die Vorlagenbibliothek: Ausgangspunkte für Prototyp, Folie, Bild und Video, die du nach Typ filtern und zum Loslegen forken kannst.</em></p>\n<h2 id=\"step-4--switch-models-mid-project\">Schritt 4 — Das Modell mitten im Projekt wechseln</h2>\n<p>Das ist Jacks Lieblingsmanöver und genau das, was Claude Design nicht kann. Öffne mitten im Projekt den Modellwechsler (unten links), wechsle von Claude Code zu <strong>Codex</strong> (oder ChatGPT, Gemini, was auch immer du verbunden hast) und speichere. Deine nächste Nachricht — „glätte den Live-Event-Stream, er wirkt ruckelig“ — wird nun vom neuen Modell bearbeitet, im selben Projekt, mit demselben Kontext.</p>\n<p>Sein Profi-Tipp: <strong>Nimm Opus, um das ursprüngliche Design festzulegen, und wechsle dann zu günstigeren Modellen, um zu iterieren und zu skalieren.</strong> Es ist für ein Modell viel einfacher, mehr vom Gleichen zu erzeugen, als einen Look von Grund auf zu entwickeln — lass also das stärkste Modell die Architektur setzen und die günstigeren die Masse erledigen.</p>\n<h2 id=\"step-5--add-ai-images-and-deploy\">Schritt 5 — KI-Bilder ergänzen und deployen</h2>\n<p>Hinterlege in den Einstellungen einen Schlüssel für einen Medienanbieter (zum Beispiel OpenAI für GPT Image), und du kannst direkt im Verlauf nach generierten Bildern fragen — „füge in einem der Kästchen ein Bild eines Investment-Sparschweins im Ghibli-Stil ein“ — und es landet direkt im Design, samt Verläufen. Diese eingebettete Generierung bietet dir ein reiner Design-Klon nicht.</p>\n<p>Wenn du fertig bist, gibt dir <strong>Teilen</strong> das vollständige Export-Menü: eigenständiges HTML, PowerPoint, PDF, ZIP, als Vorlage speichern — oder <strong>direkt zu Vercel deployen</strong> mit deinem Token. Lade es als ZIP herunter, und du kannst es auch in Codex, Claude oder dem Editor deiner Wahl wieder öffnen.</p>\n<h2 id=\"when-to-switch-and-when-not-to\">Wann du wechseln solltest (und wann nicht)</h2>\n<p>Jack ist ehrlich, was die Passung angeht. Wechsle zu Open Design, wenn du eine <strong>Agentur oder Freelancer</strong> bist und kommerziell unbedenkliche Ergebnisse brauchst, ein <strong>Multi-Modell-Anwender</strong>, der ohnehin schon für Claude Code / Codex / Cursor zahlt, oder wenn du <strong>das wöchentliche Limit von Claude Design aufbrauchst</strong> und einfach mehr Designs willst. Bleib vorerst bei Claude Design, wenn du in all das ganz neu bist und innerhalb seiner Limits zufrieden bist.</p>\n<p>Ein Vorbehalt: Open Design ist ein junges, sich schnell entwickelndes Projekt, also rechne mit gelegentlichen Ecken und Kanten und sei etwas nachsichtig — es verbessert sich rasch.</p>\n<h2 id=\"tips\">Tipps</h2>\n<ul>\n<li><strong>Importiere zuerst dein Claude-Design-ZIP</strong> — bau kein System neu, das du schon hast.</li>\n<li><strong>Lege den Look mit Opus fest, dann wechsle zu günstigeren Modellen</strong>, um zu iterieren und zu skalieren.</li>\n<li><strong>Hinterlege einen Medienschlüssel</strong>, um eingebettete KI-Bilder zu erhalten — ein echtes Upgrade gegenüber einem statischen Design-Tool.</li>\n<li><strong>Nutze eine lokale CLI</strong>, damit die Generierung über ein Abo läuft, das du ohnehin schon bezahlst, statt über Gebühren pro Aufruf.</li>\n<li><strong>Exportiere früh</strong> (HTML/ZIP/Vercel), um vor der Übergabe zu validieren.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Werden meine Claude-Design-Projekte übertragen?</strong>\nJa. Lade dein Projekt als ZIP aus Claude Design herunter und importiere dieses ZIP in Open Design — Tokens und Komponenten kommen mit.</p>\n<p><strong>Kann ich wirklich jedes Modell nutzen?</strong>\nJa — wähle aus den auf deinem Rechner installierten Agents (Claude Code, Codex, Gemini, Cursor, OpenCode und mehr), wechsle mitten im Projekt zwischen ihnen oder bring deinen eigenen API-Schlüssel mit.</p>\n<p><strong>Ist es für Kundenarbeit unbedenklich?</strong>\nJa. Open Design steht unter Apache-2.0, sodass du es kommerziell ohne Lizenzgebühren oder Genehmigung nutzen kannst — anders als manche restriktiv lizenzierten Klone.</p>\n<p><strong>Ist es kostenlos?</strong>\nDie App ist Open Source unter Apache-2.0 und kostenlos lokal ausführbar. Du zahlst nur für die Modell- und Mediennutzung des jeweiligen Agents und der Anbieter, die du verbindest — und genau so entkommst du dem festen monatlichen Limit.</p>\n<hr>\n<p><em>Dieser schriftliche Leitfaden basiert auf der praxisnahen Anleitung von Jack Roberts. Sieh dir das vollständige Video oben an und <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">abonniere Jack Roberts</a> für mehr praktische KI-Build-Analysen.</em></p>",
  },
  "fr": {
    title: "Migrer de Claude Design vers Open Design — la configuration sans limites",
    summary: "Un guide de migration pour laisser derrière soi les limites hebdomadaires de Claude Design : installez Open Design, importez votre ZIP Claude Design, construisez avec n'importe quel modèle, changez de modèle en cours de projet, ajoutez des images générées par IA et déployez. Comprend la franche question du « quand basculer ». D'après la démonstration pratique de Jack Roberts.",
    bodyHtml: "<p>Ce guide est un plan de migration pour quiconque se heurte aux limites hebdomadaires brutales de Claude Design : installez Open Design, transférez votre travail existant, construisez avec le modèle de votre choix, changez de modèle en cours de projet, ajoutez des images générées par IA et déployez — le tout en local. Il suit la migration de bout en bout que <strong>Jack Roberts</strong> réalise dans <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">sa démonstration pratique</a>, réécrite et mise à jour avec la version actuelle. Regardez la vidéo ci-dessus pour la démonstration en direct, ou poursuivez votre lecture pour la version écrite.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/01-workspace.webp\" alt=\"L'espace de travail Open Design — ce que vous découvrez après l'installation.\">\n<em>L'espace de travail Open Design — prototypes, présentations, images et vidéos réunis dans un même canevas serein et familier.</em></p>\n<h2 id=\"why-migrate-at-all\">Pourquoi migrer ?</h2>\n<p>L'argument de Jack est sans détour : Claude Design est vraiment bon, mais les limites vous arrêtent net. Vous êtes verrouillé sur un seul modèle (Opus 4.7), plafonné à environ deux designs sérieux par semaine, et vous payez de 20 à 200 $/mois en plus de ce que vous dépensez déjà pour le développement. Dès que vous voulez un modèle moins cher, un modèle différent ou concevoir à grande échelle, vous êtes freiné.</p>\n<p>Open Design fait tomber ces murs :</p>\n<ul>\n<li><strong>N'importe quel modèle</strong> — et vous pouvez en changer en cours de projet.</li>\n<li><strong>Aucune limite hebdomadaire</strong> — la génération s'appuie sur l'agent et les fournisseurs que vous utilisez déjà.</li>\n<li><strong>Apache-2.0</strong> — sûr sur le plan commercial pour le travail client, contrairement aux dépôts clones aux licences restrictives.</li>\n<li><strong>Tout en local d'abord</strong> — rien n'est téléversé ; vos projets restent sur votre machine.</li>\n</ul>\n<p>Ce point de licence compte plus qu'il n'y paraît : Jack insiste sur le fait que plusieurs « clones de Claude Design » ne peuvent en réalité pas être utilisés dans des projets clients. Apache-2.0 signifie que vous pouvez livrer du travail rémunéré construit avec, sans redevances ni autorisation.</p>\n<h2 id=\"step-1--install-open-design\">Étape 1 — Installer Open Design</h2>\n<p>Trois portes d'entrée :</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Voie</th><th>Idéale pour</th><th>Prérequis</th></tr></thead><tbody><tr><td><strong>Application de bureau</strong></td><td>La plupart des gens — zéro configuration</td><td>Aucun. Téléchargez et ouvrez, c'est tout.</td></tr><tr><td><strong>Exécuter depuis les sources</strong></td><td>Les développeurs qui veulent lire ou modifier le code</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Installer dans votre agent</strong></td><td>Ceux qui vivent dans le terminal</td><td>Un CLI d'agent de développement existant</td></tr></tbody></table>\n<p>La voie la plus simple est l'<strong>application de bureau</strong> depuis <a href=\"https://open-design.ai/download\">open-design.ai/download</a> — elle détecte automatiquement les CLI d'agents installés. Dans la vidéo, Jack emprunte la voie développeur en confiant le dépôt à son agent et en le laissant le cloner et l'exécuter :</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Cela ouvre sa propre application web locale — votre propre espace de travail à la Claude Design, hébergé localement — à l'URL dynamique qu'il affiche (ne codez pas le port en dur).</p>\n<h2 id=\"step-2--bring-your-claude-design-work-across\">Étape 2 — Transférer votre travail Claude Design</h2>\n<p>L'étape de migration que tout le monde attend : <strong>importer votre projet Claude Design</strong>. Si vous avez construit un design system ou un projet dans Claude Design, vous pouvez le reprendre tel quel — ouvrez-le là-bas, téléchargez le projet sous forme de ZIP, puis importez ce ZIP dans Open Design. Vos tokens et composants vous accompagnent, vous ne repartez donc pas de zéro.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/02-design-systems.webp\" alt=\"La bibliothèque de design systems intégrée — de vrais points de départ de marques.\">\n<em>La bibliothèque de design systems : chaque entrée décompose une vraie marque en palette, typographie, composants et atmosphère visuelle réutilisables.</em></p>\n<p>Vous héritez aussi d'une riche bibliothèque de design systems intégrée — Airbnb, Apple, Nike, PlayStation et bien d'autres — si bien que, même sans rien importer, vous pouvez choisir une marque et l'agent en hérite la voix, la typographie, la palette et le langage de mise en page.</p>\n<h2 id=\"step-3--build-with-the-model-you-choose\">Étape 3 — Construire avec le modèle de votre choix</h2>\n<p>Au premier lancement, Open Design affiche les agents déjà installés sur votre machine. Jack choisit Claude Code, nomme un projet (« analytics »), opte pour une haute fidélité et rédige un brief pour un tableau de bord façon Stripe. Open Design pose ses questions de clarification — surface, public principal, ton, périmètre, couleur d'accentuation — puis déroule une liste de tâches et produit un tableau de bord interactif d'un seul coup. Un second tour de retours le rend prêt pour la production.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/03-templates.webp\" alt=\"La bibliothèque de modèles — points de départ pour prototypes, présentations, images et vidéos.\">\n<em>La bibliothèque de modèles : des points de départ pour prototypes, présentations, images et vidéos que vous pouvez filtrer par type et dupliquer pour commencer.</em></p>\n<h2 id=\"step-4--switch-models-mid-project\">Étape 4 — Changer de modèle en cours de projet</h2>\n<p>C'est le geste préféré de Jack, et celui que Claude Design ne sait pas faire. En cours de projet, ouvrez le sélecteur de modèle (en bas à gauche), passez de Claude Code à <strong>Codex</strong> (ou ChatGPT, Gemini, tout ce que vous avez connecté), et enregistrez. Désormais votre prochain message — « lisse le flux d'événements en direct, il a l'air saccadé » — est traité par le nouveau modèle, dans le même projet, avec le même contexte.</p>\n<p>Son conseil de pro : <strong>utilisez Opus pour établir le design initial, puis basculez sur des modèles moins chers pour itérer et passer à l'échelle.</strong> Il est bien plus facile pour un modèle de produire davantage de la même chose que de concevoir une esthétique à partir de zéro ; laissez donc le modèle le plus puissant poser l'architecture et confiez le volume aux modèles moins coûteux.</p>\n<h2 id=\"step-5--add-ai-images-and-deploy\">Étape 5 — Ajouter des images générées par IA et déployer</h2>\n<p>Ajoutez une clé de fournisseur de médias (par exemple OpenAI pour GPT Image) dans les paramètres, et vous pourrez demander des images générées en ligne — « ajoute une image façon Ghibli d'une tirelire d'investissement dans l'un des encadrés » — et elle s'insère directement dans le design, dégradés compris. Cette génération intégrée est quelque chose qu'un simple clone de design ne vous offre pas.</p>\n<p>Une fois terminé, <strong>Partager</strong> vous donne le menu d'export complet : HTML autonome, PowerPoint, PDF, ZIP, enregistrer comme modèle — ou <strong>déployer directement sur Vercel</strong> avec votre token. Téléchargez sous forme de ZIP et vous pourrez aussi le rouvrir dans Codex, Claude ou l'éditeur de votre choix.</p>\n<h2 id=\"when-to-switch-and-when-not-to\">Quand basculer (et quand ne pas le faire)</h2>\n<p>Jack est honnête sur la question de l'adéquation. Passez à Open Design si vous êtes une <strong>agence ou un freelance</strong> ayant besoin d'une production sûre sur le plan commercial, un <strong>utilisateur multi-modèles</strong> qui paie déjà Claude Code / Codex / Cursor, ou si vous <strong>épuisez la limite hebdomadaire de Claude Design</strong> et voulez simplement plus de designs. Restez sur Claude Design pour l'instant si vous débutez dans tout cela et que ses limites vous conviennent.</p>\n<p>Une réserve : Open Design est un projet jeune et en évolution rapide, attendez-vous donc à quelques aspérités de temps en temps et faites-lui un peu crédit — il s'améliore vite.</p>\n<h2 id=\"tips\">Astuces</h2>\n<ul>\n<li><strong>Importez d'abord votre ZIP Claude Design</strong> — ne reconstruisez pas un système que vous possédez déjà.</li>\n<li><strong>Posez l'esthétique avec Opus, puis basculez sur des modèles moins chers</strong> pour itérer et passer à l'échelle.</li>\n<li><strong>Ajoutez une clé de médias</strong> pour obtenir des images IA en ligne — une vraie amélioration par rapport à un outil de design statique.</li>\n<li><strong>Utilisez un CLI local</strong> pour que la génération s'appuie sur un abonnement que vous payez déjà, et non sur des frais à l'appel.</li>\n<li><strong>Exportez tôt</strong> (HTML/ZIP/Vercel) pour valider avant de transmettre votre travail.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Mes projets Claude Design seront-ils transférés ?</strong>\nOui. Téléchargez votre projet sous forme de ZIP depuis Claude Design et importez ce ZIP dans Open Design — les tokens et composants sont conservés.</p>\n<p><strong>Puis-je vraiment utiliser n'importe quel modèle ?</strong>\nOui — choisissez parmi les agents installés sur votre machine (Claude Code, Codex, Gemini, Cursor, OpenCode, et plus), passez de l'un à l'autre en cours de projet, ou apportez votre propre clé API.</p>\n<p><strong>Est-ce sûr pour le travail client ?</strong>\nOui. Open Design est sous Apache-2.0, vous pouvez donc l'utiliser commercialement sans redevances ni autorisation — contrairement à certains clones aux licences restrictives.</p>\n<p><strong>Est-ce gratuit ?</strong>\nL'application est open source sous Apache-2.0 et gratuite à exécuter en local. Vous ne payez que l'usage du modèle et des médias de l'agent et des fournisseurs que vous connectez — c'est précisément ainsi que vous échappez au plafond mensuel fixe.</p>\n<hr>\n<p><em>Ce guide écrit s'appuie sur la démonstration pratique de Jack Roberts. Regardez la vidéo complète ci-dessus, et <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">abonnez-vous à Jack Roberts</a> pour d'autres décryptages concrets de constructions avec l'IA.</em></p>",
  },
  "ru": {
    title: "Переход с Claude Design на Open Design — настройка без ограничений",
    summary: "Руководство по миграции, чтобы оставить позади еженедельные лимиты Claude Design: установите Open Design, импортируйте свой ZIP из Claude Design, работайте с любой моделью, меняйте модели прямо посреди проекта, добавляйте ИИ-изображения и публикуйте результат. Включает честный разбор того, «когда стоит переходить». На основе практического разбора Джека Робертса.",
    bodyHtml: "<p>Это руководство — план миграции для всех, кто упёрся в жёсткие еженедельные лимиты Claude Design: установите Open Design, перенесите свою текущую работу, создавайте с любой моделью на ваш выбор, меняйте модели посреди проекта, добавляйте ИИ-изображения и публикуйте — и всё это локально. Оно повторяет сквозную миграцию, которую <strong>Jack Roberts</strong> проводит в <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">своём практическом разборе</a>, переписанную и приведённую в соответствие с текущим релизом. Смотрите видео выше, чтобы увидеть процесс вживую, или читайте письменную версию ниже.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/01-workspace.webp\" alt=\"Рабочее пространство Open Design — то, что вы видите сразу после установки.\">\n<em>Рабочее пространство Open Design — прототипы, презентации, изображения и видео на одном спокойном и привычном холсте.</em></p>\n<h2 id=\"why-migrate-at-all\">Зачем вообще переходить?</h2>\n<p>Аргумент Джека прямолинеен: Claude Design действительно хорош, но лимиты останавливают вас намертво. Вы привязаны к одной модели (Opus 4.7), ограничены примерно парой полноценных дизайнов в неделю и платите $20–$200 в месяц поверх того, что вы и так тратите на кодинг. В тот момент, когда вам нужна модель подешевле, другая модель или дизайн в масштабе, вас сдерживают.</p>\n<p>Open Design убирает эти стены:</p>\n<ul>\n<li><strong>Любая модель на ваш выбор</strong> — и её можно сменить посреди проекта.</li>\n<li><strong>Никакого недельного лимита</strong> — генерация работает на агенте и провайдерах, которыми вы уже пользуетесь.</li>\n<li><strong>Apache-2.0</strong> — коммерчески безопасно для клиентской работы, в отличие от клонов-репозиториев с ограничительными лицензиями.</li>\n<li><strong>Local-first</strong> — ничего не загружается в облако; ваши проекты остаются на вашей машине.</li>\n</ul>\n<p>Этот момент с лицензией важнее, чем кажется: Джек подчёркивает, что некоторые «клоны Claude Design» на самом деле нельзя использовать в клиентских проектах. Apache-2.0 означает, что вы можете выпускать платную работу, созданную с её помощью, без роялти и без чьего-либо разрешения.</p>\n<h2 id=\"step-1--install-open-design\">Шаг 1 — Установите Open Design</h2>\n<p>Три способа начать:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Способ</th><th>Лучше всего для</th><th>Требования</th></tr></thead><tbody><tr><td><strong>Десктоп-приложение</strong></td><td>Большинства людей — без настройки</td><td>Ничего. Просто скачайте и откройте.</td></tr><tr><td><strong>Запуск из исходников</strong></td><td>Разработчиков, которые хотят читать или менять код</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Установка в ваш агент</strong></td><td>Тех, кто живёт в терминале</td><td>Уже установленный CLI кодинг-агента</td></tr></tbody></table>\n<p>Самый простой путь — <strong>десктоп-приложение</strong> с <a href=\"https://open-design.ai/download\">open-design.ai/download</a> — оно автоматически определяет установленные у вас CLI агентов. В видео Джек идёт по пути разработчика, передавая репозиторий своему агенту и позволяя ему клонировать и запустить проект:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Оно открывает собственное локальное веб-приложение — ваше локально размещённое рабочее пространство в духе Claude Design — по динамическому URL, который оно выводит (не прописывайте порт жёстко).</p>\n<h2 id=\"step-2--bring-your-claude-design-work-across\">Шаг 2 — Перенесите свою работу из Claude Design</h2>\n<p>Шаг миграции, которого ждут больше всего: <strong>импортируйте свой проект из Claude Design</strong>. Если вы создали дизайн-систему или проект в Claude Design, вы можете перенести их напрямую — откройте проект там, скачайте его как ZIP, а затем импортируйте этот ZIP в Open Design. Ваши токены и компоненты переезжают вместе с вами, так что не придётся пересобирать всё с нуля.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/02-design-systems.webp\" alt=\"Встроенная библиотека дизайн-систем — реальные бренды как точки старта.\">\n<em>Библиотека дизайн-систем: каждая запись раскладывает реальный бренд на палитру, типографику, компоненты и визуальную атмосферу, которые можно переиспользовать.</em></p>\n<p>Вы также получаете в наследство глубокую встроенную библиотеку дизайн-систем — Airbnb, Apple, Nike, PlayStation и многие другие — так что даже без импорта чего-либо можно выбрать бренд, и агент перенимает его голос, типографику, палитру и язык вёрстки.</p>\n<h2 id=\"step-3--build-with-the-model-you-choose\">Шаг 3 — Создавайте с моделью, которую выбираете вы</h2>\n<p>При первом запуске Open Design показывает агентов, уже установленных на вашей машине. Джек выбирает Claude Code, называет проект («analytics»), выбирает высокую детализацию и пишет задание для дашборда в стиле Stripe. Open Design задаёт уточняющие вопросы — поверхность, основной зритель, тон, охват, акцентный цвет — затем прорабатывает список задач и выдаёт интерактивный дашборд с первого захода. Второй раунд правок доводит его до готового к продакшену состояния.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/03-templates.webp\" alt=\"Библиотека шаблонов — стартовые точки для прототипов, слайдов, изображений и видео.\">\n<em>Библиотека шаблонов: стартовые точки для прототипов, слайдов, изображений и видео, которые можно фильтровать по типу и форкать, чтобы начать.</em></p>\n<h2 id=\"step-4--switch-models-mid-project\">Шаг 4 — Меняйте модели посреди проекта</h2>\n<p>Это любимый приём Джека и то, чего Claude Design сделать не может. Посреди проекта откройте переключатель моделей (внизу слева), смените Claude Code на <strong>Codex</strong> (или ChatGPT, Gemini, что угодно, что вы подключили) и сохраните. Теперь ваше следующее сообщение — «сгладь поток прямых трансляций, он выглядит дёрганым» — обрабатывается новой моделью, в том же проекте, с тем же контекстом.</p>\n<p>Его профессиональный совет: <strong>используйте Opus, чтобы заложить первоначальный дизайн, а затем переключайтесь на модели подешевле для итераций и масштабирования.</strong> Модели гораздо проще делать «ещё больше того же самого», чем выстраивать облик с нуля, поэтому пусть самая сильная модель задаёт архитектуру, а более дешёвые берут на себя объём.</p>\n<h2 id=\"step-5--add-ai-images-and-deploy\">Шаг 5 — Добавьте ИИ-изображения и опубликуйте</h2>\n<p>Добавьте ключ медиа-провайдера (например, OpenAI для GPT Image) в настройках, и вы сможете запрашивать сгенерированные изображения прямо по ходу — «добавь в один из блоков изображение копилки для инвестиций в стиле Ghibli» — и оно сразу ложится в дизайн, со всеми градиентами. Такая встроенная генерация — то, чего чистый клон для дизайна вам не даёт.</p>\n<p>Когда вы закончите, <strong>Share</strong> открывает полное меню экспорта: автономный HTML, PowerPoint, PDF, ZIP, сохранение как шаблон — или <strong>публикация прямо в Vercel</strong> с вашим токеном. Скачайте как ZIP — и вы также сможете снова открыть проект в Codex, Claude или в любимом редакторе.</p>\n<h2 id=\"when-to-switch-and-when-not-to\">Когда переходить (а когда нет)</h2>\n<p>Джек честен насчёт того, кому это подходит. Переходите на Open Design, если вы <strong>агентство или фрилансер</strong>, которому нужен коммерчески безопасный результат, <strong>оператор с несколькими моделями</strong>, уже платящий за Claude Code / Codex / Cursor, или вы <strong>выжигаете недельный лимит Claude Design</strong> и просто хотите больше дизайнов. Пока оставайтесь на Claude Design, если вы только начинаете во всём этом разбираться и вам комфортно в его рамках.</p>\n<p>Одна оговорка: Open Design — молодой и быстро развивающийся проект, так что будьте готовы к отдельным шероховатостям и отнеситесь к нему снисходительно — он быстро улучшается.</p>\n<h2 id=\"tips\">Советы</h2>\n<ul>\n<li><strong>Сначала импортируйте свой ZIP из Claude Design</strong> — не пересобирайте систему, которая у вас уже есть.</li>\n<li><strong>Задайте облик с помощью Opus, затем переключитесь на модели подешевле</strong> для итераций и масштабирования.</li>\n<li><strong>Добавьте медиа-ключ</strong>, чтобы получать встроенные ИИ-изображения — настоящий апгрейд по сравнению со статичным инструментом для дизайна.</li>\n<li><strong>Используйте локальный CLI</strong>, чтобы генерация работала на подписке, за которую вы уже платите, а не на плате за каждый вызов.</li>\n<li><strong>Экспортируйте раньше</strong> (HTML/ZIP/Vercel), чтобы проверить результат до передачи заказчику.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Перенесутся ли мои проекты из Claude Design?</strong>\nДа. Скачайте свой проект как ZIP из Claude Design и импортируйте этот ZIP в Open Design — токены и компоненты переезжают вместе с ним.</p>\n<p><strong>Можно ли действительно использовать любую модель?</strong>\nДа — выбирайте из агентов, установленных на вашей машине (Claude Code, Codex, Gemini, Cursor, OpenCode и другие), переключайтесь между ними посреди проекта или используйте собственный API-ключ.</p>\n<p><strong>Безопасно ли это для клиентской работы?</strong>\nДа. Open Design распространяется под Apache-2.0, поэтому вы можете использовать его коммерчески без роялти и разрешений — в отличие от некоторых клонов с ограничительными лицензиями.</p>\n<p><strong>Это бесплатно?</strong>\nПриложение с открытым исходным кодом под Apache-2.0 и бесплатно для локального запуска. Вы платите только за использование модели и медиа того агента и провайдеров, которых подключаете — именно так вы и уходите от фиксированного ежемесячного лимита.</p>\n<hr>\n<p><em>Это письменное руководство основано на практическом разборе Джека Робертса. Смотрите полное видео выше и <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">подпишитесь на Jack Roberts</a>, чтобы получать больше практических разборов сборки на ИИ.</em></p>",
  },
  "es": {
    title: "Migrar de Claude Design a Open Design: la configuración sin límites",
    summary: "Una guía de migración para dejar atrás los límites semanales de Claude Design: instala Open Design, importa tu ZIP de Claude Design, crea con cualquier modelo, cambia de modelo a mitad del proyecto, añade imágenes con IA y despliega. Incluye el sincero veredicto sobre \"cuándo cambiar\". Basada en el recorrido práctico de Jack Roberts.",
    bodyHtml: "<p>Esta guía es una hoja de ruta de migración para cualquiera que esté chocando con los brutales límites semanales de Claude Design: instala Open Design, traslada tu trabajo existente, crea con el modelo que quieras, cambia de modelo a mitad del proyecto, añade imágenes con IA y despliega, todo en local. Sigue la migración integral que <strong>Jack Roberts</strong> realiza en <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">su recorrido práctico</a>, reescrita y puesta al día con la versión actual. Mira el video de arriba para verlo en vivo, o sigue leyendo para la versión escrita.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/01-workspace.webp\" alt=\"El espacio de trabajo de Open Design: lo que encuentras tras la instalación.\">\n<em>El espacio de trabajo de Open Design: prototipos, presentaciones, imágenes y video en un único lienzo sereno y familiar.</em></p>\n<h2 id=\"why-migrate-at-all\">¿Por qué migrar?</h2>\n<p>El argumento de Jack es directo: Claude Design es realmente bueno, pero los límites te frenan en seco. Estás atado a un solo modelo (Opus 4.7), con un tope de apenas un par de diseños significativos por semana, y pagando entre 20 y 200 $/mes además de lo que ya gastas en programar. En cuanto quieres un modelo más barato, un modelo distinto o diseñar a gran escala, te quedas bloqueado.</p>\n<p>Open Design derriba esos muros:</p>\n<ul>\n<li><strong>Cualquier modelo que quieras</strong>, y puedes cambiar a mitad del proyecto.</li>\n<li><strong>Sin tope semanal</strong>: la generación se apoya en el agente y los proveedores que ya usas.</li>\n<li><strong>Apache-2.0</strong>: seguro a nivel comercial para trabajo con clientes, a diferencia de los repositorios clonados con licencias restrictivas.</li>\n<li><strong>Local primero</strong>: nada se sube; tus proyectos se quedan en tu máquina.</li>\n</ul>\n<p>Ese punto sobre la licencia importa más de lo que parece: Jack insiste en que varios “clones de Claude Design” no se pueden usar realmente en proyectos de clientes. Apache-2.0 significa que puedes entregar trabajo remunerado creado con él, sin regalías ni permisos.</p>\n<h2 id=\"step-1--install-open-design\">Paso 1: Instala Open Design</h2>\n<p>Tres formas de empezar:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Vía</th><th>Mejor para</th><th>Requisitos</th></tr></thead><tbody><tr><td><strong>Aplicación de escritorio</strong></td><td>La mayoría de la gente: sin configuración</td><td>Ninguno. Solo descárgala y ábrela.</td></tr><tr><td><strong>Ejecutar desde el código fuente</strong></td><td>Desarrolladores que quieran leer o modificar el código</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Instalar en tu agente</strong></td><td>Gente que vive en la terminal</td><td>Un CLI de agente de programación existente</td></tr></tbody></table>\n<p>La vía más sencilla es la <strong>aplicación de escritorio</strong> desde <a href=\"https://open-design.ai/download\">open-design.ai/download</a>: detecta automáticamente los CLI de agente que tienes instalados. En el video, Jack opta por la ruta para desarrolladores entregando el repositorio a su agente y dejando que lo clone y lo ejecute:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abre su propia aplicación web local —tu propio espacio de trabajo alojado localmente, al estilo de Claude Design— en la URL dinámica que imprime (no fijes el puerto a mano).</p>\n<h2 id=\"step-2--bring-your-claude-design-work-across\">Paso 2: Trae tu trabajo de Claude Design</h2>\n<p>El paso de migración que más gente quiere: <strong>importa tu proyecto de Claude Design</strong>. Si creaste un sistema de diseño o un proyecto en Claude Design, puedes trasladarlo directamente: ábrelo allí, descarga el proyecto como ZIP y luego importa ese ZIP en Open Design. Tus tokens y componentes vienen contigo, así que no tienes que reconstruirlo todo desde cero.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/02-design-systems.webp\" alt=\"La biblioteca integrada de sistemas de diseño: puntos de partida de marcas reales.\">\n<em>La biblioteca de sistemas de diseño: cada entrada descompone una marca real en paleta, tipografía, componentes y atmósfera visual que puedes reutilizar.</em></p>\n<p>También heredas una completa biblioteca integrada de sistemas de diseño —Airbnb, Apple, Nike, PlayStation y muchas más—, así que incluso sin importar nada puedes elegir una marca y el agente hereda su voz, su tipografía, su paleta y su lenguaje de maquetación.</p>\n<h2 id=\"step-3--build-with-the-model-you-choose\">Paso 3: Crea con el modelo que elijas</h2>\n<p>Al iniciarse por primera vez, Open Design muestra los agentes que ya tienes instalados en tu máquina. Jack elige Claude Code, le pone nombre a un proyecto (“analytics”), opta por alta fidelidad y redacta un briefing para un panel al estilo de Stripe. Open Design hace sus preguntas aclaratorias —superficie, audiencia principal, tono, alcance, color de acento—, luego avanza por una lista de tareas y produce un panel interactivo de una sola vez. Una segunda ronda de comentarios lo deja listo para producción.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/03-templates.webp\" alt=\"La biblioteca de plantillas: puntos de partida de prototipo, presentación, imagen y video.\">\n<em>La biblioteca de plantillas: puntos de partida de prototipo, presentación, imagen y video que puedes filtrar por tipo y bifurcar para empezar.</em></p>\n<h2 id=\"step-4--switch-models-mid-project\">Paso 4: Cambia de modelo a mitad del proyecto</h2>\n<p>Esta es la jugada favorita de Jack y la que Claude Design no puede hacer. A mitad del proyecto, abre el selector de modelos (abajo a la izquierda), cambia de Claude Code a <strong>Codex</strong> (o ChatGPT, Gemini, lo que tengas conectado) y guarda. Ahora tu siguiente mensaje —“suaviza el flujo de eventos en vivo, se ve con lag”— lo gestiona el nuevo modelo, en el mismo proyecto y con el mismo contexto.</p>\n<p>Su consejo de experto: <strong>usa Opus para establecer el diseño inicial y luego cambia a modelos más baratos para iterar y escalar.</strong> A un modelo le resulta mucho más fácil producir más de lo mismo que diseñar un aspecto desde cero, así que deja que el modelo más potente fije la arquitectura y que los más baratos hagan el volumen.</p>\n<h2 id=\"step-5--add-ai-images-and-deploy\">Paso 5: Añade imágenes con IA y despliega</h2>\n<p>Añade en los ajustes la clave de un proveedor de medios (por ejemplo OpenAI para GPT Image) y podrás pedir imágenes generadas en línea —“añade una imagen al estilo Ghibli de una hucha de inversión en una de las cajas”— que se integran directamente en el diseño, con degradados incluidos. Esa generación en línea es algo que un clon de diseño puro no te ofrece.</p>\n<p>Cuando termines, <strong>Share</strong> te da el menú de exportación completo: HTML autónomo, PowerPoint, PDF, ZIP, guardar como plantilla, o <strong>desplegar directamente en Vercel</strong> con tu token. Descárgalo como ZIP y también podrás volver a abrirlo en Codex, Claude o el editor que prefieras.</p>\n<h2 id=\"when-to-switch-and-when-not-to\">Cuándo cambiar (y cuándo no)</h2>\n<p>Jack es honesto sobre para quién encaja. Cámbiate a Open Design si eres una <strong>agencia o un profesional autónomo</strong> que necesita resultados seguros a nivel comercial, un <strong>operador multimodelo</strong> que ya paga por Claude Code / Codex / Cursor, o si estás <strong>consumiendo el tope semanal de Claude Design</strong> y simplemente quieres más diseños. Quédate con Claude Design por ahora si todo esto es nuevo para ti y te sientes a gusto dentro de sus límites.</p>\n<p>Una advertencia: Open Design es un proyecto joven y de rápida evolución, así que cuenta con alguna aspereza ocasional y dale un margen: está mejorando deprisa.</p>\n<h2 id=\"tips\">Consejos</h2>\n<ul>\n<li><strong>Importa primero tu ZIP de Claude Design</strong>: no reconstruyas un sistema que ya tienes.</li>\n<li><strong>Define el aspecto con Opus y luego cambia a modelos más baratos</strong> para iterar y escalar.</li>\n<li><strong>Añade una clave de medios</strong> para obtener imágenes con IA en línea: una mejora real frente a una herramienta de diseño estática.</li>\n<li><strong>Usa un CLI local</strong> para que la generación se apoye en una suscripción que ya pagas, en lugar de tarifas por llamada.</li>\n<li><strong>Exporta pronto</strong> (HTML/ZIP/Vercel) para validar antes de hacer la entrega.</li>\n</ul>\n<h2 id=\"faq\">Preguntas frecuentes</h2>\n<p><strong>¿Se transferirán mis proyectos de Claude Design?</strong>\nSí. Descarga tu proyecto como ZIP desde Claude Design e impórtalo en Open Design: los tokens y componentes se trasladan.</p>\n<p><strong>¿De verdad puedo usar cualquier modelo?</strong>\nSí: elige entre los agentes instalados en tu máquina (Claude Code, Codex, Gemini, Cursor, OpenCode y más), cambia entre ellos a mitad del proyecto o usa tu propia clave de API.</p>\n<p><strong>¿Es seguro para el trabajo con clientes?</strong>\nSí. Open Design usa la licencia Apache-2.0, así que puedes utilizarlo comercialmente sin regalías ni permisos, a diferencia de algunos clones con licencias restrictivas.</p>\n<p><strong>¿Es gratis?</strong>\nLa aplicación es de código abierto bajo Apache-2.0 y gratuita para ejecutarla en local. Solo pagas por el uso de modelo y medios del agente y los proveedores que conectes, que es exactamente como escapas del tope mensual fijo.</p>\n<hr>\n<p><em>Esta guía escrita está basada en el recorrido práctico de Jack Roberts. Mira el video completo arriba y <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">suscríbete a Jack Roberts</a> para más análisis prácticos de construcción con IA.</em></p>",
  },
  "pt-br": {
    title: "Migrando do Claude Design para o Open Design — A configuração sem limites",
    summary: "Um manual de migração para deixar para trás os limites semanais do Claude Design — instale o Open Design, importe seu ZIP do Claude Design, construa com qualquer modelo, troque de modelo no meio do projeto, adicione imagens de IA e faça o deploy. Inclui a avaliação honesta de \"quando trocar\". Baseado no passo a passo prático de Jack Roberts.",
    bodyHtml: "<p>Este guia é um manual de migração para qualquer pessoa que esteja esbarrando nos limites semanais brutais do Claude Design: instale o Open Design, traga seu trabalho existente, construa com qualquer modelo que você quiser, troque de modelo no meio do projeto, adicione imagens de IA e faça o deploy — tudo localmente. Ele segue a migração completa que <strong>Jack Roberts</strong> conduz em <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">seu passo a passo prático</a>, reescrito e atualizado com a versão atual. Assista ao vídeo acima para ver a execução ao vivo, ou continue lendo para a versão escrita.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/01-workspace.webp\" alt=\"O workspace do Open Design — o que você encontra após a instalação.\">\n<em>O workspace do Open Design — protótipos, apresentações de slides, imagens e vídeo em um único canvas tranquilo e familiar.</em></p>\n<h2 id=\"why-migrate-at-all\">Por que migrar afinal?</h2>\n<p>O argumento de Jack é direto: o Claude Design é genuinamente bom, mas os limites te paralisam. Você fica preso a um único modelo (Opus 4.7), limitado a cerca de um par de designs relevantes por semana, e pagando US$ 20–US$ 200/mês por cima do que você já gasta com programação. No momento em que você quiser um modelo mais barato, um modelo diferente, ou projetar em escala, você fica travado.</p>\n<p>O Open Design derruba essas barreiras:</p>\n<ul>\n<li><strong>Qualquer modelo que você quiser</strong> — e você pode trocar no meio do projeto.</li>\n<li><strong>Sem limite semanal</strong> — a geração roda sobre o agente e os provedores que você já usa.</li>\n<li><strong>Apache-2.0</strong> — comercialmente seguro para trabalho com clientes, ao contrário de repositórios clones com licenças restritivas.</li>\n<li><strong>Local-first</strong> — nada é enviado para a nuvem; seus projetos ficam na sua máquina.</li>\n</ul>\n<p>Esse ponto sobre a licença importa mais do que parece: Jack enfatiza que vários “clones do Claude Design” não podem, na prática, ser usados em projetos de clientes. Apache-2.0 significa que você pode entregar trabalho pago construído com ele, sem royalties, sem precisar de permissão.</p>\n<h2 id=\"step-1--install-open-design\">Passo 1 — Instale o Open Design</h2>\n<p>Três formas de começar:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Caminho</th><th>Melhor para</th><th>Requisitos</th></tr></thead><tbody><tr><td><strong>App de desktop</strong></td><td>A maioria das pessoas — configuração zero</td><td>Nenhum. Basta baixar e abrir.</td></tr><tr><td><strong>Rodar a partir do código-fonte</strong></td><td>Desenvolvedores que querem ler ou modificar o código</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Instalar no seu agente</strong></td><td>Pessoas que vivem no terminal</td><td>Uma CLI de coding-agent já instalada</td></tr></tbody></table>\n<p>O caminho mais simples é o <strong>app de desktop</strong> em <a href=\"https://open-design.ai/download\">open-design.ai/download</a> — ele detecta automaticamente as CLIs de agentes que você já tem instaladas. No vídeo, Jack segue o caminho de desenvolvedor entregando o repositório ao seu agente e deixando-o clonar e executar:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Ele abre seu próprio app web local — seu workspace hospedado localmente, no estilo Claude Design — na URL dinâmica que ele imprime (não fixe a porta no código).</p>\n<h2 id=\"step-2--bring-your-claude-design-work-across\">Passo 2 — Traga seu trabalho do Claude Design</h2>\n<p>O passo de migração que as pessoas mais querem: <strong>importar seu projeto do Claude Design</strong>. Se você construiu um design system ou projeto no Claude Design, você pode trazê-lo diretamente — abra-o lá, baixe o projeto como um ZIP e depois importe esse ZIP no Open Design. Seus tokens e componentes vêm junto, então você não precisa reconstruir do zero.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/02-design-systems.webp\" alt=\"A biblioteca integrada de design systems — pontos de partida de marcas reais.\">\n<em>A biblioteca de design systems: cada item decompõe uma marca real em paleta, tipografia, componentes e atmosfera visual que você pode reutilizar.</em></p>\n<p>Você também herda uma profunda biblioteca integrada de design systems — Airbnb, Apple, Nike, PlayStation, e muitas outras — então, mesmo sem importar nada, você pode escolher uma marca e o agente herda sua voz, tipografia, paleta e linguagem de layout.</p>\n<h2 id=\"step-3--build-with-the-model-you-choose\">Passo 3 — Construa com o modelo que você escolher</h2>\n<p>No primeiro lançamento, o Open Design mostra os agentes já instalados na sua máquina. Jack escolhe o Claude Code, dá um nome ao projeto (“analytics”), opta por alta fidelidade e escreve um briefing para um dashboard no estilo Stripe. O Open Design faz suas perguntas de esclarecimento — superfície, público principal, tom, escopo, cor de destaque — e então percorre uma lista de tarefas e produz um dashboard interativo de uma só vez. Uma segunda rodada de feedback o deixa pronto para produção.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/03-templates.webp\" alt=\"A biblioteca de templates — pontos de partida de protótipo, slide, imagem e vídeo.\">\n<em>A biblioteca de templates: pontos de partida de protótipo, slide, imagem e vídeo que você pode filtrar por tipo e bifurcar para começar.</em></p>\n<h2 id=\"step-4--switch-models-mid-project\">Passo 4 — Troque de modelo no meio do projeto</h2>\n<p>Esse é o movimento favorito de Jack e o que o Claude Design não consegue fazer. No meio do projeto, abra o seletor de modelos (canto inferior esquerdo), mude do Claude Code para o <strong>Codex</strong> (ou ChatGPT, Gemini, qualquer um que você tenha conectado) e salve. Agora sua próxima mensagem — “suavize o stream de eventos ao vivo, ele parece travado” — é tratada pelo novo modelo, no mesmo projeto, com o mesmo contexto.</p>\n<p>A dica profissional dele: <strong>use o Opus para estabelecer o design inicial, depois mude para modelos mais baratos para iterar e escalar.</strong> É muito mais fácil para um modelo produzir mais do mesmo do que criar uma aparência a partir de princípios fundamentais, então deixe o modelo mais forte definir a arquitetura e deixe os mais baratos fazerem o volume.</p>\n<h2 id=\"step-5--add-ai-images-and-deploy\">Passo 5 — Adicione imagens de IA e faça o deploy</h2>\n<p>Adicione uma chave de provedor de mídia (por exemplo, OpenAI para GPT Image) nas configurações, e você poderá pedir imagens geradas direto no fluxo — “adicione uma imagem em estilo Ghibli de um cofrinho de investimento em uma das caixas” — e ela cai direto no design, com gradientes e tudo. Essa geração inline é algo que um clone puramente de design não te oferece.</p>\n<p>Quando você terminar, o <strong>Compartilhar</strong> te dá o menu completo de exportação: HTML autônomo, PowerPoint, PDF, ZIP, salvar como template — ou <strong>fazer deploy direto na Vercel</strong> com seu token. Baixe como um ZIP e você também poderá reabri-lo no Codex, Claude ou no editor de sua preferência.</p>\n<h2 id=\"when-to-switch-and-when-not-to\">Quando trocar (e quando não trocar)</h2>\n<p>Jack é honesto sobre o encaixe. Troque para o Open Design se você for uma <strong>agência ou freelancer</strong> que precisa de saída comercialmente segura, um <strong>operador multimodelo</strong> que já paga por Claude Code / Codex / Cursor, ou se você está <strong>estourando o limite semanal do Claude Design</strong> e só quer mais designs. Fique com o Claude Design por enquanto se você é totalmente novo em tudo isso e está satisfeito dentro dos limites dele.</p>\n<p>Uma ressalva: o Open Design é um projeto jovem e em rápido movimento, então espere alguma aspereza ocasional e dê um pouco de paciência — ele está melhorando rapidamente.</p>\n<h2 id=\"tips\">Dicas</h2>\n<ul>\n<li><strong>Importe seu ZIP do Claude Design primeiro</strong> — não reconstrua um sistema que você já tem.</li>\n<li><strong>Defina a aparência com o Opus, depois mude para modelos mais baratos</strong> para iterar e escalar.</li>\n<li><strong>Adicione uma chave de mídia</strong> para obter imagens de IA inline — um upgrade real em relação a uma ferramenta de design estática.</li>\n<li><strong>Use uma CLI local</strong> para que a geração rode sobre uma assinatura que você já paga, e não taxas por chamada.</li>\n<li><strong>Exporte cedo</strong> (HTML/ZIP/Vercel) para validar antes de fazer a entrega.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Meus projetos do Claude Design vão ser transferidos?</strong>\nSim. Baixe seu projeto como um ZIP do Claude Design e importe esse ZIP no Open Design — tokens e componentes vêm junto.</p>\n<p><strong>Posso realmente usar qualquer modelo?</strong>\nSim — escolha entre os agentes instalados na sua máquina (Claude Code, Codex, Gemini, Cursor, OpenCode, e mais), alterne entre eles no meio do projeto, ou traga sua própria chave de API.</p>\n<p><strong>É seguro para trabalho com clientes?</strong>\nSim. O Open Design é Apache-2.0, então você pode usá-lo comercialmente sem royalties ou permissão — ao contrário de alguns clones com licenças restritivas.</p>\n<p><strong>É gratuito?</strong>\nO app é open source sob Apache-2.0 e gratuito para rodar localmente. Você paga apenas pelo uso de modelo e mídia de qualquer agente e provedores que você conectar — que é exatamente como você escapa do limite mensal fixo.</p>\n<hr>\n<p><em>Este guia escrito é baseado no passo a passo prático de Jack Roberts. Assista ao vídeo completo acima e <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">inscreva-se no canal de Jack Roberts</a> para mais análises práticas de construção com IA.</em></p>",
  },
  "it": {
    title: "Migrare da Claude Design a Open Design — la configurazione senza limiti",
    summary: "Una guida pratica alla migrazione per lasciarsi alle spalle i limiti settimanali di Claude Design: installa Open Design, importa il tuo file ZIP di Claude Design, lavora con qualsiasi modello, cambia modello a metà progetto, aggiungi immagini AI e pubblica. Include l'onesta valutazione su \"quando passare\". Basata sulla guida pratica di Jack Roberts.",
    bodyHtml: "<p>Questa guida è una procedura di migrazione per chiunque si scontri con i durissimi limiti settimanali di Claude Design: installa Open Design, porta con te il lavoro che hai già fatto, lavora con qualsiasi modello tu voglia, cambia modello a metà progetto, aggiungi immagini AI e pubblica — tutto in locale. Segue la migrazione end-to-end che <strong>Jack Roberts</strong> esegue nella <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">sua guida pratica</a>, riscritta e aggiornata all'attuale release. Guarda il video qui sopra per la dimostrazione dal vivo, oppure continua a leggere per la versione scritta.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/01-workspace.webp\" alt=\"L'area di lavoro di Open Design — ciò che trovi dopo l'installazione.\">\n<em>L'area di lavoro di Open Design — prototipi, presentazioni, immagini e video in un'unica tela ordinata e familiare.</em></p>\n<h2 id=\"why-migrate-at-all\">Perché migrare?</h2>\n<p>La tesi di Jack è schietta: Claude Design è davvero valido, ma i limiti ti bloccano sul nascere. Sei vincolato a un solo modello (Opus 4.7), limitato a circa un paio di design significativi a settimana, e paghi 20–200 $/mese in aggiunta a qualsiasi cosa già spendi per la programmazione. Nel momento in cui vuoi un modello più economico, un modello diverso o progettare su larga scala, sei frenato.</p>\n<p>Open Design abbatte queste barriere:</p>\n<ul>\n<li><strong>Qualsiasi modello tu voglia</strong> — e puoi cambiarlo a metà progetto.</li>\n<li><strong>Nessun limite settimanale</strong> — la generazione si appoggia all'agente e ai provider che già usi.</li>\n<li><strong>Apache-2.0</strong> — sicuro a livello commerciale per il lavoro con i clienti, a differenza dei repository clone con licenze restrittive.</li>\n<li><strong>Local-first</strong> — nulla viene caricato online; i tuoi progetti restano sulla tua macchina.</li>\n</ul>\n<p>Quel punto sulla licenza conta più di quanto sembri: Jack sottolinea che diversi \"cloni di Claude Design\" non possono in realtà essere usati nei progetti per i clienti. Apache-2.0 significa che puoi consegnare lavoro a pagamento realizzato con esso, senza royalty e senza chiedere permessi.</p>\n<h2 id=\"step-1--install-open-design\">Passo 1 — Installa Open Design</h2>\n<p>Tre modi per iniziare:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Percorso</th><th>Ideale per</th><th>Requisiti</th></tr></thead><tbody><tr><td><strong>App desktop</strong></td><td>La maggior parte delle persone — zero configurazione</td><td>Nessuno. Basta scaricare e aprire.</td></tr><tr><td><strong>Eseguire dal codice sorgente</strong></td><td>Sviluppatori che vogliono leggere o modificare il codice</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Installare nel tuo agente</strong></td><td>Chi vive nel terminale</td><td>Una CLI di coding-agent già esistente</td></tr></tbody></table>\n<p>Il percorso più semplice è l'<strong>app desktop</strong> da <a href=\"https://open-design.ai/download\">open-design.ai/download</a> — rileva automaticamente le CLI degli agenti che hai installato. Nel video, Jack segue il percorso da sviluppatore consegnando il repository al suo agente e lasciando che lo cloni ed esegua:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Si apre una sua web app locale — la tua area di lavoro ospitata localmente, simile a Claude Design — all'URL dinamico che stampa a schermo (non scrivere la porta come valore fisso).</p>\n<h2 id=\"step-2--bring-your-claude-design-work-across\">Passo 2 — Porta con te il lavoro fatto su Claude Design</h2>\n<p>Il passo di migrazione che le persone desiderano di più: <strong>importa il tuo progetto di Claude Design</strong>. Se hai costruito un design system o un progetto in Claude Design, puoi trasferirlo direttamente — aprilo lì, scarica il progetto come file ZIP, poi importa quel file ZIP in Open Design. I tuoi token e componenti vengono con te, così non devi ricostruire tutto da zero.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/02-design-systems.webp\" alt=\"La libreria di design system integrata — veri punti di partenza basati sui brand.\">\n<em>La libreria di design system: ogni voce scompone un brand reale in palette, tipografia, componenti e atmosfera visiva che puoi riutilizzare.</em></p>\n<p>Erediti anche una ricca libreria di design system integrata — Airbnb, Apple, Nike, PlayStation e molti altri — così, anche senza importare nulla, puoi scegliere un brand e l'agente ne eredita la voce, la tipografia, la palette e il linguaggio di layout.</p>\n<h2 id=\"step-3--build-with-the-model-you-choose\">Passo 3 — Lavora con il modello che scegli</h2>\n<p>Al primo avvio, Open Design mostra gli agenti già installati sulla tua macchina. Jack sceglie Claude Code, dà un nome a un progetto (\"analytics\"), opta per l'alta fedeltà e scrive un brief per una dashboard in stile Stripe. Open Design pone le sue domande di chiarimento — superficie, destinatario principale, tono, ambito, colore d'accento — poi procede attraverso una lista di attività e produce una dashboard interattiva in un colpo solo. Un secondo giro di feedback la rende pronta per la produzione.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/03-templates.webp\" alt=\"La libreria di template — punti di partenza per prototipi, slide, immagini e video.\">\n<em>La libreria di template: punti di partenza per prototipi, slide, immagini e video che puoi filtrare per tipo e fare il fork per iniziare.</em></p>\n<h2 id=\"step-4--switch-models-mid-project\">Passo 4 — Cambia modello a metà progetto</h2>\n<p>Questa è la mossa preferita di Jack, ed è quella che Claude Design non può fare. A metà progetto, apri il selettore dei modelli (in basso a sinistra), passa da Claude Code a <strong>Codex</strong> (oppure ChatGPT, Gemini, qualsiasi cosa tu abbia collegato) e salva. Ora il tuo messaggio successivo — \"smussa lo stream dell'evento dal vivo, sembra a scatti\" — viene gestito dal nuovo modello, nello stesso progetto, con lo stesso contesto.</p>\n<p>Il suo consiglio da esperto: <strong>usa Opus per impostare il design iniziale, poi passa a modelli più economici per iterare e scalare.</strong> Per un modello è molto più facile fare altro dello stesso tipo che ingegnerizzare un look partendo da zero, quindi lascia che il modello più potente definisca l'architettura e lascia che quelli più economici facciano il lavoro di volume.</p>\n<h2 id=\"step-5--add-ai-images-and-deploy\">Passo 5 — Aggiungi immagini AI e pubblica</h2>\n<p>Aggiungi nelle impostazioni una chiave per un provider di media (per esempio OpenAI per GPT Image) e potrai richiedere immagini generate direttamente nel flusso — \"aggiungi un'immagine in stile Ghibli di un salvadanaio per gli investimenti in uno dei riquadri\" — che finisce dritta nel design, gradienti compresi. Questa generazione inline è qualcosa che un puro clone di design non ti offre.</p>\n<p>Quando hai finito, <strong>Condividi</strong> ti dà il menu di esportazione completo: HTML autonomo, PowerPoint, PDF, ZIP, salva come template — oppure <strong>pubblica direttamente su Vercel</strong> con il tuo token. Scarica come file ZIP e potrai anche riaprirlo in Codex, Claude o l'editor che preferisci.</p>\n<h2 id=\"when-to-switch-and-when-not-to\">Quando passare (e quando no)</h2>\n<p>Jack è onesto sull'adeguatezza. Passa a Open Design se sei un'<strong>agenzia o un freelancer</strong> che ha bisogno di output sicuro a livello commerciale, un <strong>operatore multi-modello</strong> che già paga per Claude Code / Codex / Cursor, oppure se stai <strong>bruciando il limite settimanale di Claude Design</strong> e vuoi semplicemente più design. Per ora resta su Claude Design se sei alle primissime armi con tutto questo e ti trovi bene entro i suoi limiti.</p>\n<p>Un'avvertenza: Open Design è un progetto giovane e in rapida evoluzione, quindi aspettati qualche imperfezione occasionale e concedigli un po' di indulgenza — sta migliorando velocemente.</p>\n<h2 id=\"tips\">Consigli</h2>\n<ul>\n<li><strong>Importa prima il tuo file ZIP di Claude Design</strong> — non ricostruire un sistema che hai già.</li>\n<li><strong>Definisci il look con Opus, poi passa a modelli più economici</strong> per iterare e scalare.</li>\n<li><strong>Aggiungi una chiave per i media</strong> per ottenere immagini AI inline — un vero salto di qualità rispetto a uno strumento di design statico.</li>\n<li><strong>Usa una CLI locale</strong> così la generazione si appoggia a un abbonamento che già paghi, invece di tariffe per chiamata.</li>\n<li><strong>Esporta presto</strong> (HTML/ZIP/Vercel) per validare prima di consegnare.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>I miei progetti di Claude Design verranno trasferiti?</strong>\nSì. Scarica il tuo progetto come file ZIP da Claude Design e importa quel file ZIP in Open Design — token e componenti vengono trasferiti.</p>\n<p><strong>Posso davvero usare qualsiasi modello?</strong>\nSì — scegli tra gli agenti installati sulla tua macchina (Claude Code, Codex, Gemini, Cursor, OpenCode e altri), passa dall'uno all'altro a metà progetto, oppure usa la tua chiave API.</p>\n<p><strong>È sicuro per il lavoro con i clienti?</strong>\nSì. Open Design è Apache-2.0, quindi puoi usarlo a scopo commerciale senza royalty né permessi — a differenza di alcuni cloni con licenze restrittive.</p>\n<p><strong>È gratuito?</strong>\nL'app è open source con licenza Apache-2.0 ed è gratuita da eseguire in locale. Paghi solo per l'utilizzo del modello e dei media dell'agente e dei provider che colleghi — che è esattamente il modo in cui sfuggi al limite mensile fisso.</p>\n<hr>\n<p><em>Questa guida scritta è basata sulla guida pratica di Jack Roberts. Guarda il video completo qui sopra e <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">iscriviti al canale di Jack Roberts</a> per altre analisi pratiche su come costruire con l'AI.</em></p>",
  },
  "tr": {
    title: "Claude Design'dan Open Design'a Geçiş — Sınırsız Kurulum",
    summary: "Claude Design'ın haftalık sınırlarını geride bırakmak için bir geçiş kılavuzu — Open Design'ı kurun, Claude Design ZIP'inizi içe aktarın, istediğiniz modelle tasarlayın, proje ortasında model değiştirin, AI görselleri ekleyin ve dağıtın. Dürüst \"ne zaman geçiş yapmalı\" değerlendirmesini de içerir. Jack Roberts'ın uygulamalı anlatımına dayanmaktadır.",
    bodyHtml: "<p>Bu rehber, Claude Design'ın acımasız haftalık sınırlarına takılan herkes için bir geçiş kılavuzu: Open Design'ı kurun, mevcut çalışmalarınızı taşıyın, istediğiniz herhangi bir modelle tasarlayın, proje ortasında model değiştirin, AI görselleri ekleyin ve dağıtın — hepsi yerel olarak. <strong>Jack Roberts</strong>'ın <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">uygulamalı anlatımında</a> baştan sona yürüttüğü geçişi takip eder, güncel sürüme göre yeniden yazılmış ve güncellenmiştir. Canlı çalışma için yukarıdaki videoyu izleyin veya yazılı sürüm için okumaya devam edin.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/01-workspace.webp\" alt=\"Open Design çalışma alanı — kurulumdan sonra karşılaştığınız ekran.\">\n<em>Open Design çalışma alanı — prototipler, slayt sunumları, görseller ve video tek bir sakin, tanıdık tuvalde.</em></p>\n<h2 id=\"why-migrate-at-all\">Neden geçiş yapmalı ki?</h2>\n<p>Jack'in gerekçesi açık: Claude Design gerçekten iyi, ancak sınırlar sizi durduruyor. Tek bir modele (Opus 4.7) kilitlisiniz, haftada yaklaşık birkaç anlamlı tasarımla sınırlısınız ve zaten kodlamaya harcadığınız paranın üzerine ayda 20–200 dolar ödüyorsunuz. Daha ucuz bir model, farklı bir model istediğiniz ya da büyük ölçekte tasarım yapmak istediğiniz an, geride kalıyorsunuz.</p>\n<p>Open Design bu duvarları kaldırır:</p>\n<ul>\n<li><strong>İstediğiniz herhangi bir model</strong> — ve proje ortasında değiştirebilirsiniz.</li>\n<li><strong>Haftalık sınır yok</strong> — üretim, zaten kullandığınız agent ve sağlayıcılar üzerinden çalışır.</li>\n<li><strong>Apache-2.0</strong> — kısıtlayıcı lisanslı klon depoların aksine, müşteri işleri için ticari olarak güvenli.</li>\n<li><strong>Yerel öncelikli</strong> — hiçbir şey yüklenmez; projeleriniz makinenizde kalır.</li>\n</ul>\n<p>O lisans noktası kulağa geldiğinden daha önemli: Jack, birçok \"Claude Design klonunun\" aslında müşteri projelerinde kullanılamayacağının altını çiziyor. Apache-2.0, onunla oluşturulan ücretli işleri telif hakkı bedeli veya izin olmadan teslim edebileceğiniz anlamına gelir.</p>\n<h2 id=\"step-1--install-open-design\">Adım 1 — Open Design'ı kurun</h2>\n<p>Üç giriş yolu:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Yol</th><th>En uygun olduğu kişiler</th><th>Gereksinimler</th></tr></thead><tbody><tr><td><strong>Masaüstü uygulaması</strong></td><td>Çoğu kişi — sıfır yapılandırma</td><td>Yok. Sadece indirin ve açın.</td></tr><tr><td><strong>Kaynaktan çalıştırma</strong></td><td>Kodu okumak veya değiştirmek isteyen geliştiriciler</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Agent'ınıza kurma</strong></td><td>Terminalde yaşayanlar</td><td>Mevcut bir kodlama-agent CLI'ı</td></tr></tbody></table>\n<p>En basit yol, <a href=\"https://open-design.ai/download\">open-design.ai/download</a> adresindeki <strong>masaüstü uygulamasıdır</strong> — kurulu agent CLI'larınızı otomatik olarak algılar. Videoda Jack, depoyu agent'ına vererek ve klonlayıp çalıştırmasına izin vererek geliştirici yolunu izler:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Kendi yerel web uygulamasını açar — kendinize ait, yerel olarak barındırılan, Claude-Design benzeri bir çalışma alanı — yazdırdığı dinamik URL'de (portu sabit kodlamayın).</p>\n<h2 id=\"step-2--bring-your-claude-design-work-across\">Adım 2 — Claude Design çalışmalarınızı taşıyın</h2>\n<p>İnsanların en çok istediği geçiş adımı: <strong>Claude Design projenizi içe aktarın</strong>. Claude Design'da bir tasarım sistemi veya proje oluşturduysanız, onu doğrudan taşıyabilirsiniz — orada açın, projeyi ZIP olarak indirin, ardından o ZIP'i Open Design'a aktarın. Token'larınız ve bileşenleriniz sizinle gelir, böylece sıfırdan yeniden oluşturmazsınız.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/02-design-systems.webp\" alt=\"Yerleşik tasarım sistemleri kütüphanesi — gerçek marka başlangıç noktaları.\">\n<em>Tasarım sistemleri kütüphanesi: her girdi, gerçek bir markayı yeniden kullanabileceğiniz palet, tipografi, bileşenler ve görsel atmosfere ayırır.</em></p>\n<p>Ayrıca derin bir yerleşik tasarım sistemleri kütüphanesini de devralırsınız — Airbnb, Apple, Nike, PlayStation ve çok daha fazlası — böylece hiçbir şey içe aktarmadan bile bir marka seçebilir ve agent onun sesini, tipografisini, paletini ve düzen dilini devralır.</p>\n<h2 id=\"step-3--build-with-the-model-you-choose\">Adım 3 — Seçtiğiniz modelle tasarlayın</h2>\n<p>İlk açılışta Open Design, makinenizde halihazırda kurulu olan agent'ları gösterir. Jack, Claude Code'u seçer, bir projeye ad verir (\"analytics\"), yüksek çözünürlük seçer ve Stripe tarzı bir gösterge paneli için bir brief yazar. Open Design açıklayıcı sorularını sorar — yüzey, birincil görüntüleyen, ton, kapsam, vurgu — ardından bir yapılacaklar listesini çalışarak tek seferde etkileşimli bir gösterge paneli üretir. İkinci bir geri bildirim turu onu üretime hazır hale getirir.</p>\n<p><img src=\"/tutorials/open-design-replacing-claude-design-jack-roberts/03-templates.webp\" alt=\"Şablon kütüphanesi — prototip, slayt, görsel ve video başlangıç noktaları.\">\n<em>Şablon kütüphanesi: türe göre filtreleyip başlamak için çatallayabileceğiniz prototip, slayt, görsel ve video başlangıç noktaları.</em></p>\n<h2 id=\"step-4--switch-models-mid-project\">Adım 4 — Proje ortasında model değiştirin</h2>\n<p>Bu, Jack'in en sevdiği hamle ve Claude Design'ın yapamadığı şey. Proje ortasında model değiştiriciyi açın (sol altta), Claude Code'dan <strong>Codex</strong>'e (veya ChatGPT, Gemini, bağladığınız herhangi bir şeye) geçin ve kaydedin. Şimdi bir sonraki mesajınız — \"canlı etkinlik akışını düzgünleştir, takılıyor gibi görünüyor\" — aynı projede, aynı bağlamla yeni model tarafından işlenir.</p>\n<p>Onun profesyonel ipucu: <strong>başlangıç tasarımını oluşturmak için Opus kullanın, ardından yinelemek ve ölçeklemek için daha ucuz modellere geçin.</strong> Bir modelin aynısından daha fazlasını üretmesi, bir görünümü ilk ilkelerden tasarlamasından çok daha kolaydır, bu yüzden mimariyi en güçlü modelin kurmasına ve hacmi daha ucuz modellerin yapmasına izin verin.</p>\n<h2 id=\"step-5--add-ai-images-and-deploy\">Adım 5 — AI görselleri ekleyin ve dağıtın</h2>\n<p>Ayarlarda bir medya sağlayıcısı anahtarı ekleyin (örneğin GPT Image için OpenAI) ve satır içinde üretilmiş görseller isteyebilirsiniz — \"kutulardan birine Ghibli tarzı bir yatırım kumbarası görseli ekle\" — ve bu, doğrudan tasarımın içine, gradyanlarıyla birlikte düşer. Bu satır içi üretim, salt tasarım klonunun size vermediği bir şeydir.</p>\n<p>İşiniz bittiğinde, <strong>Paylaş</strong> size tam dışa aktarma menüsünü verir: bağımsız HTML, PowerPoint, PDF, ZIP, şablon olarak kaydet — ya da token'ınızla <strong>doğrudan Vercel'e dağıtın</strong>. ZIP olarak indirin, böylece onu Codex, Claude veya tercih ettiğiniz editörde yeniden açabilirsiniz.</p>\n<h2 id=\"when-to-switch-and-when-not-to\">Ne zaman geçiş yapmalı (ve ne zaman yapmamalı)</h2>\n<p>Jack, uygunluk konusunda dürüst. Ticari olarak güvenli çıktıya ihtiyaç duyan bir <strong>ajans veya serbest çalışansanız</strong>, zaten Claude Code / Codex / Cursor için ödeme yapan bir <strong>çok modelli kullanıcıysanız</strong> ya da <strong>Claude Design'ın haftalık sınırını tüketiyorsanız</strong> ve sadece daha fazla tasarım istiyorsanız Open Design'a geçin. Tüm bunlara yeni başlıyorsanız ve sınırları içinde mutluysanız, şimdilik Claude Design'da kalın.</p>\n<p>Bir uyarı: Open Design genç, hızla gelişen bir proje, bu yüzden ara sıra pürüzler bekleyin ve ona biraz tolerans gösterin — hızla iyileşiyor.</p>\n<h2 id=\"tips\">İpuçları</h2>\n<ul>\n<li><strong>Önce Claude Design ZIP'inizi içe aktarın</strong> — zaten sahip olduğunuz bir sistemi yeniden oluşturmayın.</li>\n<li><strong>Görünümü Opus ile belirleyin, ardından daha ucuz modellere geçin</strong> — yineleme ve ölçekleme için.</li>\n<li><strong>Bir medya anahtarı ekleyin</strong> — satır içi AI görselleri elde etmek için; statik bir tasarım aracına göre gerçek bir yükseltme.</li>\n<li><strong>Yerel bir CLI kullanın</strong> — böylece üretim, çağrı başına ücretler yerine zaten ödediğiniz bir abonelik üzerinden çalışır.</li>\n<li><strong>Erken dışa aktarın</strong> (HTML/ZIP/Vercel) — teslim etmeden önce doğrulamak için.</li>\n</ul>\n<h2 id=\"faq\">SSS</h2>\n<p><strong>Claude Design projelerim aktarılacak mı?</strong>\nEvet. Projenizi Claude Design'dan ZIP olarak indirin ve o ZIP'i Open Design'a aktarın — token'lar ve bileşenler taşınır.</p>\n<p><strong>Gerçekten herhangi bir modeli kullanabilir miyim?</strong>\nEvet — makinenizde kurulu olan agent'lardan seçin (Claude Code, Codex, Gemini, Cursor, OpenCode ve daha fazlası), proje ortasında aralarında geçiş yapın veya kendi API anahtarınızı getirin.</p>\n<p><strong>Müşteri işleri için güvenli mi?</strong>\nEvet. Open Design Apache-2.0 lisanslıdır, bu yüzden kısıtlayıcı lisanslı bazı klonların aksine, telif hakkı bedeli veya izin olmadan ticari olarak kullanabilirsiniz.</p>\n<p><strong>Ücretsiz mi?</strong>\nUygulama Apache-2.0 altında açık kaynaklıdır ve yerel olarak çalıştırması ücretsizdir. Yalnızca bağladığınız agent ve sağlayıcıların model ve medya kullanımı için ödeme yaparsınız — sabit aylık sınırdan kaçmanın yolu tam olarak budur.</p>\n<hr>\n<p><em>Bu yazılı rehber, Jack Roberts'ın uygulamalı anlatımına dayanmaktadır. Yukarıdaki tam videoyu izleyin ve daha fazla pratik AI geliştirme analizi için <a href=\"https://www.youtube.com/watch?v=ju-T6uQNPSg\">Jack Roberts'a abone olun</a>.</em></p>",
  },
};
